/* ------------------------------------------------------------
   GESTION DE SESSION (jeton de connexion)
   Stockée dans le navigateur si possible (localStorage), sinon en
   mémoire pour la session en cours. Toujours protégée par try/catch
   pour fonctionner aussi bien en ligne que dans l'aperçu.
   ------------------------------------------------------------ */
const _sessionMemoire = { valeur: null };
function lireSession(){
  try{
    const s = window.localStorage.getItem("gea_session");
    return s ? JSON.parse(s) : null;
  }catch(e){ return _sessionMemoire.valeur; }
}
function ecrireSession(session){
  _sessionMemoire.valeur = session;
  try{
    if(session) window.localStorage.setItem("gea_session", JSON.stringify(session));
    else        window.localStorage.removeItem("gea_session");
  }catch(e){ /* mode mémoire seule */ }
}

// Appel générique à l'API d'authentification Supabase
async function appelAuth(chemin, corps){
  const r = await fetch(SUPABASE_URL + "/auth/v1" + chemin, {
    method: "POST",
    headers: { "Content-Type":"application/json", "apikey":SUPABASE_ANON_KEY },
    body: JSON.stringify(corps),
  });
  const data = await r.json().catch(()=> ({}));
  if(!r.ok){
    const msg = data.error_description || data.msg || data.error || ("Erreur " + r.status);
    throw new Error(msg);
  }
  return data;
}

function sessionDepuisReponse(data){
  return {
    access_token:  data.access_token,
    refresh_token: data.refresh_token,
    user:          data.user,
    expire_le:     Date.now() + ((data.expires_in || 3600) * 1000),
  };
}

// Connexion par email + mot de passe
async function connexionEmail(email, motDePasse){
  const data = await appelAuth("/token?grant_type=password",
    { email: email.trim().toLowerCase(), password: motDePasse });
  const session = sessionDepuisReponse(data);
  ecrireSession(session);
  return session;
}

// Création d'un compte (le client choisit son mot de passe)
async function inscriptionEmail(email, motDePasse){
  const data = await appelAuth("/signup",
    { email: email.trim().toLowerCase(), password: motDePasse });
  if(data.access_token){            // si la confirmation par email est désactivée
    const session = sessionDepuisReponse(data);
    ecrireSession(session);
    return { session };
  }
  return { session: null };         // sinon : email de confirmation envoyé
}

// Demande de réinitialisation du mot de passe (email de récupération)
async function motDePasseOublie(email){
  await appelAuth("/recover", { email: email.trim().toLowerCase() });
}

// Enregistre le NOUVEAU mot de passe à partir du jeton reçu dans le lien email.
// Appelle l'API Supabase (PUT /user) avec ce jeton de récupération.
async function definirNouveauMotDePasse(jetonRecuperation, nouveauMotDePasse){
  const r = await fetch(SUPABASE_URL + "/auth/v1/user", {
    method: "PUT",
    headers: {
      "Content-Type":  "application/json",
      "apikey":        SUPABASE_ANON_KEY,
      "Authorization": "Bearer " + jetonRecuperation,
    },
    body: JSON.stringify({ password: nouveauMotDePasse }),
  });
  const data = await r.json().catch(()=> ({}));
  if(!r.ok){
    const msg = data.error_description || data.msg || data.error || ("Erreur " + r.status);
    throw new Error(msg);
  }
  return data;
}

// Lit le lien de récupération reçu par email (Supabase place le jeton dans l'adresse,
// après le « # »). Renvoie :
//   { jeton }   -> on doit afficher l'écran « nouveau mot de passe »
//   { erreur }  -> le lien est invalide ou expiré (message à montrer)
//   null        -> adresse normale, rien à faire
function lireLienRecuperation(){
  try{
    const brut = (window.location.hash || "").replace(/^#/, "");
    if(!brut) return null;
    const p = new URLSearchParams(brut);
    if(p.get("error") || p.get("error_description")){
      const detail = (p.get("error_code") || "") + " " + (p.get("error_description") || p.get("error") || "");
      return { erreur: /expired|otp_expired/i.test(detail)
        ? "Ce lien de réinitialisation a expiré. Demandez-en un nouveau via « Mot de passe oublié ? »."
        : "Ce lien de réinitialisation n'est pas valide. Demandez-en un nouveau." };
    }
    if(p.get("type") === "recovery" && p.get("access_token")){
      return { jeton: p.get("access_token") };
    }
    return null;
  }catch(e){ return null; }
}

// Retire le jeton de l'adresse une fois lu (il ne doit pas rester visible dans le navigateur).
function nettoyerAdresse(){
  try{
    window.history.replaceState(null, "", window.location.pathname + window.location.search);
  }catch(e){ /* sans effet si l'historique n'est pas disponible */ }
}

// Rafraîchit un jeton expiré ; renvoie la nouvelle session ou null
async function rafraichirSession(){
  const s = lireSession();
  if(!s || !s.refresh_token) return null;
  try{
    const data = await appelAuth("/token?grant_type=refresh_token",
      { refresh_token: s.refresh_token });
    const session = sessionDepuisReponse(data);
    ecrireSession(session);
    return session;
  }catch(e){ ecrireSession(null); return null; }
}

function deconnexion(){ ecrireSession(null); }

// Appel d'une fonction Supabase (RPC) AVEC le jeton du compte connecté.
// Réessaie une fois après rafraîchissement si le jeton a expiré.
async function appelRPC(nom, params, _reessai){
  let session = lireSession();
  const jeton = session ? session.access_token : SUPABASE_ANON_KEY;
  const r = await fetch(SUPABASE_URL + "/rest/v1/rpc/" + nom, {
    method: "POST",
    headers: {
      "Content-Type":  "application/json",
      "apikey":        SUPABASE_ANON_KEY,
      "Authorization": "Bearer " + jeton,
    },
    body: JSON.stringify(params || {}),
  });
  if(r.status === 401 && !_reessai){
    const nouvelle = await rafraichirSession();
    if(nouvelle) return appelRPC(nom, params, true);
    throw new Error("Session expirée. Merci de vous reconnecter.");
  }
  if(!r.ok) throw new Error("Erreur serveur (" + r.status + ")");
  return await r.json();
}

/* ------------------------------------------------------------
   DOCUMENTS DES TERRAINS — dialogue avec le stockage privé
   Espace de stockage protégé : seuls l'administrateur (ajout /
   suppression) et les clients à jour de leurs frais de dossier
   (lecture) y ont accès. Les règles sont appliquées côté serveur.
   ------------------------------------------------------------ */
const BUCKET_DOCS = "documents-terrains";

// Appel authentifié au stockage, avec un réessai après rafraîchissement du jeton.
async function appelStockage(methode, chemin, options, _reessai){
  options = options || {};
  const session = lireSession();
  if(!session) throw new Error("NON_CONNECTE");
  const entetes = {
    "apikey":        SUPABASE_ANON_KEY,
    "Authorization": "Bearer " + session.access_token,
  };
  if(options.contentType) entetes["Content-Type"] = options.contentType;
  if(options.entetesSup)  Object.assign(entetes, options.entetesSup);
  const rep = await fetch(SUPABASE_URL + "/storage/v1" + chemin, {
    method: methode, headers: entetes, body: options.corps,
  });
  if(rep.status === 401 && !_reessai){
    const nouvelle = await rafraichirSession();
    if(nouvelle) return appelStockage(methode, chemin, options, true);
  }
  return rep;
}

// Liste les documents d'un site : renvoie [{ nom, chemin }]
async function listerDocuments(idSite){
  const rep = await appelStockage("POST", "/object/list/" + BUCKET_DOCS, {
    contentType: "application/json",
    corps: JSON.stringify({ prefix: idSite + "/", limit: 200, offset: 0,
      sortBy: { column: "name", order: "asc" } }),
  });
  if(!rep.ok) return [];
  const liste = await rep.json().catch(()=> []);
  return (Array.isArray(liste) ? liste : [])
    .filter(o => o && o.name && o.name !== ".emptyFolderPlaceholder" && o.id !== null)
    .map(o => {
      const nom = o.name.indexOf(idSite + "/") === 0 ? o.name.slice(idSite.length + 1) : o.name;
      return { nom, chemin: idSite + "/" + nom };
    });
}

// Récupère un document en mémoire pour l'afficher (aucun lien téléchargeable n'est exposé)
async function apercuDocument(chemin){
  const rep = await appelStockage("GET",
    "/object/authenticated/" + BUCKET_DOCS + "/" + encodeURI(chemin), {});
  if(!rep.ok) throw new Error("LECTURE_IMPOSSIBLE");
  const blob = await rep.blob();
  return URL.createObjectURL(blob);
}

// Téléverse un document (administrateur uniquement — vérifié côté serveur)
async function televerserDocument(idSite, fichier){
  const nomNet = (fichier.name || "document").replace(/[^a-zA-Z0-9._-]/g, "_");
  const chemin = idSite + "/" + Date.now() + "-" + nomNet;
  const rep = await appelStockage("POST",
    "/object/" + BUCKET_DOCS + "/" + encodeURI(chemin), {
      contentType: fichier.type || "application/octet-stream",
      entetesSup: { "x-upsert": "true" },
      corps: fichier,
    });
  if(!rep.ok){
    const t = await rep.text().catch(()=> "");
    throw new Error(rep.status === 403 ? "DROITS_INSUFFISANTS" : (t || "ENVOI_IMPOSSIBLE"));
  }
  return chemin;
}

// Supprime un document (administrateur uniquement — vérifié côté serveur)
async function supprimerDocument(chemin){
  const rep = await appelStockage("DELETE", "/object/" + BUCKET_DOCS, {
    contentType: "application/json",
    corps: JSON.stringify({ prefixes: [chemin] }),
  });
  if(!rep.ok) throw new Error("SUPPRESSION_IMPOSSIBLE");
  return true;
}

// Type d'un document d'après son extension (pour l'affichage)
function typeDocument(nom){
  const ext = String(nom).split(".").pop().toLowerCase();
  if(["jpg","jpeg","png","gif","webp","bmp","svg"].includes(ext)) return "image";
  if(ext === "pdf") return "pdf";
  return "autre";
}

