// Mise en forme d'un montant en FCFA (séparateur de milliers : espace insécable)
function formaterFCFA(montant){
  const n = Math.round(Number(montant) || 0);
  return n.toLocaleString("fr-FR").replace(/\u00A0/g," ") + " FCFA";
}
// Conversion d'une saisie texte en nombre entier (on retire tout sauf les chiffres)
function versNombre(valeur){
  return parseInt(String(valeur).replace(/[^\d]/g,""), 10) || 0;
}
// Ajoute "nb" mois à une date et renvoie un libellé "mois année"
function dateFin(nbMois){
  const d = new Date();
  d.setMonth(d.getMonth() + nbMois);
  return d.toLocaleDateString("fr-FR",{ month:"long", year:"numeric" });
}
// Construit le lien WhatsApp (wa.me) pré-rempli vers le conseiller "numero", à partir d'une demande de souscription
function lienWhatsAppLead(f, site, ref, numero){
  const L = [];
  L.push("Bonjour GEA-HOLDING,");
  L.push("Je souhaite souscrire à un terrain. Voici ma demande :");
  L.push("");
  L.push("— IDENTITÉ —");
  L.push(`Civilité : ${f.civilite}`);
  L.push(`Nom : ${f.nom}`);
  L.push(`Prénoms : ${f.prenoms}`);
  if(f.profession) L.push(`Profession : ${f.profession}`);
  L.push("");
  L.push("— CONTACT —");
  L.push(`Téléphone : ${f.telephone}`);
  if(f.email)     L.push(`E-mail : ${f.email}`);
  if(f.residence) L.push(`Résidence : ${f.residence}`);
  L.push("");
  L.push("— PROJET —");
  L.push(`Site : ${site.ville} — ${site.quartier}`);
  L.push(`Mode : ${f.mode === "comptant" ? "Comptant" : "Échelonné"}`);
  if(f.mode === "echelonne"){
    if(f.apport)     L.push(`Apport : ${formaterFCFA(versNombre(f.apport))}`);
    if(f.mensualite) L.push(`Mensualité : ${formaterFCFA(versNombre(f.mensualite))}`);
  }
  L.push("");
  L.push(`Référence dossier : ${ref}`);
  return `https://wa.me/${numero}?text=${encodeURIComponent(L.join("\n"))}`;
}
// Construit le lien WhatsApp pré-rempli pour TRANSMETTRE un dossier de souscription
// au service commercial, à partir d'un enregistrement "s" du registre (table souscriptions).
function lienWhatsAppCommercial(s, numero){
  const echelonne = s.mode !== "comptant";
  const mont = (v)=> formaterFCFA(Number(v) || 0);
  const L = [];
  const add = (label, val)=>{ if(val !== undefined && val !== null && String(val).trim() !== "") L.push(label + " : " + val); };

  L.push("Bonjour,");
  L.push("Dossier de souscription à concrétiser (vérifié par le conseiller) :");
  L.push("");
  L.push("RÉFÉRENCE : " + (s.reference || "—"));
  if(s.cree_le) L.push("Souscrit le : " + new Date(s.cree_le).toLocaleString("fr-FR"));
  L.push("");
  L.push("— IDENTITÉ —");
  add("Civilité", s.civilite);
  add("Nom", s.nom);
  add("Prénoms", s.prenoms);
  add("Naissance", [s.naissance, s.lieu_naissance].filter(Boolean).join(" à "));
  add("Nationalité", s.nationalite);
  add("Profession", s.profession);
  add("Pièce", [s.type_piece, s.num_piece].filter(Boolean).join(" "));
  L.push("");
  L.push("— CONTACT —");
  add("Téléphone", s.telephone);
  add("E-mail", s.email);
  add("Résidence", s.residence);
  if(s.contact_nom || s.contact_tel) add("Personne à prévenir", [s.contact_nom, s.contact_tel].filter(Boolean).join(" — "));
  L.push("");
  L.push("— PROJET —");
  add("Site", nomSite(s.site_id));
  add("Mode de paiement", echelonne ? "Échelonné" : "Comptant");
  if(echelonne){
    if(s.apport)     add("Apport", mont(s.apport));
    if(s.mensualite) add("Mensualité", mont(s.mensualite));
  }
  add("Frais de dossier", mont(FRAIS_DOSSIER));
  L.push("");
  L.push("— MONTANT —");
  if(echelonne){
    add("Prix du terrain", mont(PRIX_TERRAIN));
    add("Montant global (terrain + frais)", mont(PRIX_TERRAIN + FRAIS_DOSSIER));
  } else {
    add("Prix comptant", mont(PRIX_COMPTANT));
    add("À régler (comptant + frais)", mont(PRIX_COMPTANT + FRAIS_DOSSIER));
  }
  return "https://wa.me/" + numero + "?text=" + encodeURIComponent(L.join("\n"));
}
// Affiche un numéro stocké "2250708812234" sous forme lisible "+225 07 08 81 22 34"
function formaterTel(numero){
  const n = String(numero).replace(/[^\d]/g,"");
  const local = n.startsWith("225") ? n.slice(3) : n;
  const groupes = local.replace(/(\d{2})(?=\d)/g, "$1 ").trim();
  return "+225 " + groupes;
}
// Compression d'une image avant stockage (redimension + JPEG) -> renvoie une dataURL
function compresserImage(fichier, largeurMax = 1280, qualite = 0.62){
  return new Promise((resolve)=>{
    const lecteur = new FileReader();
    lecteur.onload = (e)=>{
      const img = new Image();
      img.onload = ()=>{
        const ratio = Math.min(1, largeurMax / img.width);
        const l = Math.round(img.width * ratio);
        const h = Math.round(img.height * ratio);
        const toile = document.createElement("canvas");
        toile.width = l; toile.height = h;
        toile.getContext("2d").drawImage(img, 0, 0, l, h);
        resolve(toile.toDataURL("image/jpeg", qualite));
      };
      img.src = e.target.result;
    };
    lecteur.readAsDataURL(fichier);
  });
}
// Stockage persistant des photos ajoutées via l'admin.
// Utilise window.storage si disponible (aperçu Claude), sinon localStorage
// (site en ligne), et reste sans erreur si aucun stockage n'est accessible.
async function chargerPhotos(idSite){
  const cle = "gea_photos_" + idSite;
  try{
    if(typeof window !== "undefined" && window.storage && window.storage.get){
      const r = await window.storage.get(cle);
      return r && r.value ? JSON.parse(r.value) : [];
    }
    const v = window.localStorage.getItem(cle);
    return v ? JSON.parse(v) : [];
  }catch(e){ return []; }
}
async function sauvegarderPhotos(idSite, listePhotos){
  const cle = "gea_photos_" + idSite;
  try{
    if(typeof window !== "undefined" && window.storage && window.storage.set){
      await window.storage.set(cle, JSON.stringify(listePhotos));
    }else{
      window.localStorage.setItem(cle, JSON.stringify(listePhotos));
    }
  }catch(e){ /* stockage indisponible : les photos restent visibles pour la session */ }
}

