/* ============================================================
   GALERIE PHOTO / VIDÉO  (cage vide + import admin + plein écran)
   Variables en français : modeAdmin, gererImport, supprimerMedia
   ============================================================ */
function Galerie({ site, medias, modeAdmin, gererImport, supprimerMedia }){
  const [index, setIndex] = useState(0);     // média actuellement affiché en grand
  const [plein, setPlein] = useState(false); // vue plein écran ouverte ?
  const champFichier = useRef(null);

  // on garde l'index dans les bornes si la liste change
  useEffect(()=>{ if(index > medias.length - 1) setIndex(Math.max(0, medias.length - 1)); }, [medias.length, index]);

  const actuel = medias[index];
  const precedent = ()=> setIndex(i => (i - 1 + medias.length) % medias.length);
  const suivant   = ()=> setIndex(i => (i + 1) % medias.length);

  return (
    <div>
      {/* --- grand cadre --- */}
      <div className={"gal-cadre" + (medias.length ? " plein" : "")}>
        {medias.length === 0 ? (
          /* cage vide */
          <div className="gal-vide">
            <ImageIcon/>
            <div className="l1">{modeAdmin ? "Importez vos photos et vidéos" : "Visuels à venir"}</div>
            <div className="l2">{site.ville} — {site.quartier} · Morcellement 400 m²</div>
            {modeAdmin && (
              <button className="btn btn-or btn-sm" style={{marginTop:12}}
                onClick={()=>champFichier.current && champFichier.current.click()}>
                <Upload size={15}/> Importer des photos
              </button>
            )}
          </div>
        ) : (
          <>
            {actuel && actuel.type === "video"
              ? <video className="gal-media" src={actuel.url} controls playsInline/>
              : <img className="gal-media" src={actuel ? actuel.url : ""} alt={site.ville}/>}

            {/* superposition (nom du site + quartier + morcellement) */}
            <div className="gal-superpose">
              <div className="site">{site.ville}</div>
              <div className="quartier">{site.quartier}</div>
              <div className="morc">Morcellement 400 m²</div>
            </div>

            {/* flèches précédent / suivant */}
            {medias.length > 1 && (
              <>
                <button className="gal-fleche g" onClick={precedent}><ChevronLeft size={20} color="#13502E"/></button>
                <button className="gal-fleche d" onClick={suivant}><ChevronRight size={20} color="#13502E"/></button>
              </>
            )}

            {/* zoom plein écran */}
            {actuel && actuel.type !== "video" && (
              <button className="gal-zoom" onClick={()=>setPlein(true)}><Maximize2/></button>
            )}

            {/* bouton import (admin) */}
            {modeAdmin && (
              <div className="gal-import">
                <button className="btn btn-or btn-sm"
                  onClick={()=>champFichier.current && champFichier.current.click()}>
                  <Upload size={14}/> Ajouter
                </button>
              </div>
            )}
          </>
        )}
      </div>

      {/* --- bande de miniatures --- */}
      {medias.length > 0 && (
        <div className="miniatures">
          {medias.map((m, i)=>(
            <div key={i} className={"mini" + (i === index ? " sel" : "")} onClick={()=>setIndex(i)}>
              {m.type === "video"
                ? <><video src={m.url}/><div className="vid-ic"><Play/></div></>
                : <img src={m.url} alt=""/>}
              {modeAdmin && (
                <button className="mini-supp" onClick={(e)=>{ e.stopPropagation(); supprimerMedia(site.id, i); }}>
                  <X/>
                </button>
              )}
            </div>
          ))}
          {modeAdmin && (
            <button className="mini-add" onClick={()=>champFichier.current && champFichier.current.click()}>
              <Plus size={18}/>
            </button>
          )}
        </div>
      )}

      {/* champ de fichiers masqué (photos + vidéos) */}
      <input ref={champFichier} type="file" accept="image/*,video/*" multiple
        style={{display:"none"}}
        onChange={(e)=>{ gererImport(site.id, e.target.files); e.target.value=""; }}/>

      {/* --- vue plein écran (gros plan) --- */}
      {plein && actuel && (
        <div className="plein-fond" onClick={()=>setPlein(false)}>
          <button className="plein-fermer" onClick={()=>setPlein(false)}><X size={22}/></button>
          {medias.length > 1 && (
            <button className="plein-nav" style={{left:14}}
              onClick={(e)=>{ e.stopPropagation(); precedent(); }}><ChevronLeft size={24}/></button>
          )}
          {actuel.type === "video"
            ? <video className="plein-media" src={actuel.url} controls autoPlay onClick={(e)=>e.stopPropagation()}/>
            : <img className="plein-media" src={actuel.url} alt="" onClick={(e)=>e.stopPropagation()}/>}
          {medias.length > 1 && (
            <button className="plein-nav" style={{right:14}}
              onClick={(e)=>{ e.stopPropagation(); suivant(); }}><ChevronRight size={24}/></button>
          )}
        </div>
      )}
    </div>
  );
}

