/* ============================================================
   SECTION 3 — SIMULATEUR INTELLIGENT (cœur de l'outil)
   ============================================================ */
function Simulateur({ allerA }){
  const [idSite, setIdSite] = useState("yam");
  const [mode, setMode] = useState("echelonne");       // "echelonne" | "comptant"
  const [apportTexte, setApportTexte] = useState("500000");
  const [mensualiteTexte, setMensualiteTexte] = useState("75000");

  const site = SITES.find(s => s.id === idSite);
  const apport = versNombre(apportTexte);
  const mensualite = versNombre(mensualiteTexte);

  // --- calculs automatiques (mode échelonné) ---
  const solde = Math.max(0, PRIX_TERRAIN - apport);                       // solde restant à payer
  const nbMensualites = mensualite > 0 ? Math.ceil(solde / mensualite) : 0;
  const annees = nbMensualites / 12;
  const resteAvecFrais = solde + FRAIS_DOSSIER;                           // reste à régler (+ frais dossier)
  const montantGlobal = PRIX_TERRAIN + FRAIS_DOSSIER;                     // 2 880 000

  // --- contrôles d'éligibilité ---
  const apportOk = apport >= APPORT_MIN;
  const mensualiteOk = mensualite >= MENSUALITE_MIN;
  const dureeOk = nbMensualites <= DUREE_MAX;
  const soldeNul = solde === 0;
  const eligible = soldeNul || (apportOk && mensualiteOk && dureeOk);
  const saisiComplete = apport > 0 && mensualite > 0;

  // --- suggestions si la durée dépasse 48 mois ---
  const mensualiteRequise = Math.ceil(solde / DUREE_MAX);
  const apportRequis = PRIX_TERRAIN - mensualite * DUREE_MAX;

  // --- conseil GEA-HOLDING (gain de temps si on augmente la mensualité) ---
  const mensualitePlus = mensualite + 25000;
  const nbPlus = mensualitePlus > 0 ? Math.ceil(solde / mensualitePlus) : 0;
  const gainMois = nbMensualites - nbPlus;

  // pourcentage de couverture par l'apport (barre unique "avancement vers la propriété")
  const pctApport = Math.min(100, Math.round((apport / PRIX_TERRAIN) * 100));

  const champMontant = (label, val, set, aide) => (
    <div className="champ-bloc">
      <label className="champ-label">{label}</label>
      <div className="champ-wrap">
        <input className="champ champ-mont" inputMode="numeric" placeholder="0"
          value={val ? versNombre(val).toLocaleString("fr-FR") : ""}
          onChange={(e)=>set(String(versNombre(e.target.value) || ""))}/>
        <span className="champ-unite">FCFA</span>
      </div>
      {aide && <div className="champ-aide">{aide}</div>}
    </div>
  );

  return (
    <div className="page">
      <div className="eyebrow">Plan de financement</div>
      <h1 className="titre-page">Simulateur</h1>
      <p className="sous-titre">Saisissez vos montants, votre plan se calcule en direct.</p>

      {/* choix du site */}
      <div className="champ-label" style={{marginBottom:8}}>1 · Votre site</div>
      <div style={{display:"flex",gap:8,marginBottom:18,flexWrap:"wrap"}}>
        {SITES.map(s=>(
          <button key={s.id} onClick={()=>setIdSite(s.id)}
            style={{flex:"1 1 30%",padding:"11px 8px",borderRadius:13,border:"1.5px solid",
              borderColor: idSite===s.id ? "var(--vert-700)" : "var(--gris-200)",
              background: idSite===s.id ? "var(--vert-50)" : "#fff",textAlign:"left"}}>
            <div style={{fontSize:13,fontWeight:800,color: idSite===s.id ? "var(--vert-800)":"var(--encre)"}}>{s.ville}</div>
            <div style={{fontSize:10.5,color:"var(--gris-500)",fontWeight:600}}>{s.quartier}</div>
          </button>
        ))}
      </div>

      {/* mode de paiement */}
      <div className="champ-label" style={{marginBottom:8}}>2 · Mode de paiement</div>
      <div style={{display:"flex",background:"var(--gris-100)",borderRadius:13,padding:4,marginBottom:18}}>
        {[["echelonne","Échelonné"],["comptant","Comptant"]].map(([k,l])=>(
          <button key={k} onClick={()=>setMode(k)}
            style={{flex:1,padding:"10px",borderRadius:10,fontWeight:700,fontSize:13.5,
              background: mode===k ? "#fff":"transparent",
              color: mode===k ? "var(--vert-800)":"var(--gris-500)",
              boxShadow: mode===k ? "var(--ombre)":"none"}}>{l}</button>
        ))}
      </div>

      {/* informations fixes */}
      <div className="carte carte-pad" style={{marginBottom:18}}>
        <div className="eyebrow" style={{marginBottom:10}}>Informations du terrain</div>
        <div className="info-fixe"><span className="lbl"><CircleDot size={14}/>Surface</span><span className="val">400 m²</span></div>
        <div className="info-fixe"><span className="lbl"><CircleDot size={14}/>Prix du terrain</span><span className="val">{formaterFCFA(PRIX_TERRAIN)}</span></div>
        <div className="info-fixe"><span className="lbl"><CircleDot size={14}/>Prix comptant</span><span className="val">{formaterFCFA(PRIX_COMPTANT)}</span></div>
        <div className="info-fixe"><span className="lbl"><CircleDot size={14}/>Frais de dossier</span><span className="val">{formaterFCFA(FRAIS_DOSSIER)}</span></div>
        <div className="info-fixe"><span className="lbl"><CircleDot size={14}/>Apport minimum</span><span className="val">{formaterFCFA(APPORT_MIN)}</span></div>
        <div className="info-fixe"><span className="lbl"><CircleDot size={14}/>Mensualité minimum</span><span className="val">{formaterFCFA(MENSUALITE_MIN)}</span></div>
        <div className="info-fixe"><span className="lbl"><CircleDot size={14}/>Durée maximale</span><span className="val">48 mois</span></div>
      </div>

      {/* ====================== MODE COMPTANT ====================== */}
      {mode === "comptant" ? (
        <div className="carte carte-pad">
          <div className="eyebrow" style={{marginBottom:10}}>Paiement au comptant</div>
          <div className="info-fixe"><span className="lbl">Prix comptant</span><span className="val">{formaterFCFA(PRIX_COMPTANT)}</span></div>
          <div className="info-fixe"><span className="lbl">Frais de dossier</span><span className="val">{formaterFCFA(FRAIS_DOSSIER)}</span></div>
          <div className="res-case forte" style={{marginTop:12}}>
            <div className="res-lbl"><Wallet size={13}/>Total à régler</div>
            <div className="res-val">{formaterFCFA(PRIX_COMPTANT + FRAIS_DOSSIER)}</div>
          </div>
          <div className="conseil" style={{marginTop:14}}>
            <div className="ic"><Sparkles/></div>
            <div>
              <div className="ttl">CONSEIL GEA-HOLDING</div>
              <div className="txt">Au comptant, vous économisez <b>{formaterFCFA(PRIX_TERRAIN - PRIX_COMPTANT)}</b> par rapport au paiement échelonné, et devenez propriétaire immédiatement.</div>
            </div>
          </div>
          <button className="btn btn-vert" style={{marginTop:16}} onClick={()=>allerA("souscription")}>
            <FileText size={17}/> Souscrire au comptant
          </button>
        </div>
      ) : (
      /* ====================== MODE ÉCHELONNÉ ====================== */
      <>
        <div className="champ-label" style={{marginBottom:8}}>3 · Vos montants</div>
        <div className="carte carte-pad" style={{marginBottom:18}}>
          {champMontant("Apport initial", apportTexte, setApportTexte,
            apportOk ? null : "Minimum requis : 300 000 FCFA")}
          {champMontant("Mensualité souhaitée", mensualiteTexte, setMensualiteTexte,
            mensualiteOk ? null : "Minimum requis : 35 000 FCFA")}
        </div>

        {saisiComplete && (
          <>
            {/* CARTE DE RÉSULTATS */}
            <div className="carte" style={{marginBottom:16}}>
              <div style={{background:"linear-gradient(135deg,#13502E,#1A6138)",padding:"16px 18px",
                display:"flex",alignItems:"center",justifyContent:"space-between"}}>
                <div>
                  <div style={{color:"#E9C25A",fontSize:11,fontWeight:800,letterSpacing:"1px"}}>VOTRE PLAN — {site.ville.toUpperCase()}</div>
                  <div style={{color:"#fff",fontSize:13,marginTop:2}}>Récapitulatif personnalisé</div>
                </div>
                <Receipt size={26} color="rgba(255,255,255,.6)"/>
              </div>
              <div className="carte-pad">
                <div className="res-grille">
                  <div className="res-case"><div className="res-lbl"><Wallet size={13}/>Apport versé</div><div className="res-val">{formaterFCFA(apport)}</div></div>
                  <div className="res-case"><div className="res-lbl"><Banknote size={13}/>Solde restant</div><div className="res-val">{formaterFCFA(solde)}</div></div>
                  <div className="res-case"><div className="res-lbl"><Calendar size={13}/>Mensualités</div><div className="res-val">{nbMensualites} mois</div></div>
                  <div className="res-case"><div className="res-lbl"><Clock size={13}/>Durée</div><div className="res-val">{annees.toFixed(1).replace(".",",")} an{annees>=2?"s":""}</div></div>
                  <div className="res-case forte">
                    <div className="res-lbl"><TrendingUp size={13}/>Fin de paiement prévue</div>
                    <div className="res-val" style={{textTransform:"capitalize"}}>{soldeNul ? "Immédiate" : dateFin(nbMensualites)}</div>
                  </div>
                </div>

                <div style={{fontSize:11.5,color:"var(--gris-400)",marginTop:12,textAlign:"center"}}>
                  Montant global (terrain + dossier) : <b style={{color:"var(--gris-700)"}}>{formaterFCFA(montantGlobal)}</b> ·
                  reste à régler : <b style={{color:"var(--gris-700)"}}>{formaterFCFA(resteAvecFrais)}</b>
                </div>

                {/* BARRE UNIQUE — avancement vers la propriété */}
                <div className="prog-cadre" style={{marginTop:16}}>
                  <div className="prog-tete">
                    <span>Avancement vers la propriété</span><span>{pctApport}%</span>
                  </div>
                  <div className="prog-piste"><div className="prog-rempli" style={{width:pctApport+"%"}}/></div>
                  <div style={{fontSize:11,color:"var(--gris-400)",marginTop:6}}>
                    Part du terrain déjà couverte par votre apport.
                  </div>
                </div>
              </div>
            </div>

            {/* ALERTE INTELLIGENTE (> 48 mois) */}
            {!dureeOk && !soldeNul && (
              <div className="alerte" style={{marginBottom:16}}>
                <AlertTriangle size={20}/>
                <div>
                  <div className="ttl">Durée au-delà de 48 mois</div>
                  <div className="txt">
                    Avec cette configuration, le remboursement s'étend sur <b>{nbMensualites} mois</b>.
                    Pour rester dans la limite de 48 mois, portez votre mensualité à
                    <b> {formaterFCFA(mensualiteRequise)}</b>
                    {apportRequis > apport && <> , ou votre apport à <b>{formaterFCFA(apportRequis)}</b></>}.
                  </div>
                </div>
              </div>
            )}

            {/* BLOC ÉLIGIBILITÉ */}
            {eligible && (
              <div className="carte carte-pad" style={{marginBottom:16,borderColor:"var(--vert-100)",
                background:"linear-gradient(180deg,#fff,var(--vert-50))"}}>
                <div style={{fontWeight:800,fontSize:14,color:"var(--vert-800)",marginBottom:6,
                  display:"flex",alignItems:"center",gap:7}}>
                  <ShieldCheck size={18}/> Félicitations, votre dossier est éligible
                </div>
                <div className="elig"><span className="pastille"><Check/></span> Vous êtes éligible</div>
                <div className="elig"><span className="pastille"><Check/></span> Votre budget est compatible avec ce projet</div>
                <div className="elig"><span className="pastille"><Check/></span> Vous pouvez devenir propriétaire grâce à ce plan</div>
              </div>
            )}

            {/* CONSEIL GEA-HOLDING */}
            {!soldeNul && gainMois > 0 && (
              <div className="conseil" style={{marginBottom:16}}>
                <div className="ic"><Sparkles/></div>
                <div>
                  <div className="ttl">CONSEIL GEA-HOLDING</div>
                  <div className="txt">
                    Si vous augmentez votre mensualité de <b>{formaterFCFA(mensualite)}</b> à
                    <b> {formaterFCFA(mensualitePlus)}</b>, vous terminez en <b>{nbPlus} mois</b> au lieu
                    de {nbMensualites} — soit <b>{gainMois} mois plus tôt</b>.
                  </div>
                </div>
              </div>
            )}

            {eligible && (
              <button className="btn btn-vert" onClick={()=>allerA("souscription")}>
                <FileText size={17}/> Je souscris à ce plan <ArrowRight size={16}/>
              </button>
            )}
          </>
        )}
      </>
      )}
    </div>
  );
}

/* ============================================================
   SECTION 4 — DOCUMENTS DES TERRAINS
   Accès réservé aux clients ayant souscrit ET réglé leurs frais
   de dossier. Documents en consultation seule (non téléchargeables).
   Présentation : 3 colonnes par site. Ajout / suppression réservés
   à l'administrateur connecté. La sécurité est appliquée côté serveur.
   ============================================================ */
function Documents(){
  const [etape, setEtape]           = useState("verif");   // verif | connexion | refuse | pret
  const [estAdmin, setEstAdmin]     = useState(false);
  const [parSite, setParSite]       = useState({});        // { yam:[{nom,chemin,url,type}], ... }
  const [chargement, setChargement] = useState(false);
  const [erreur, setErreur]         = useState("");
  const [apercu, setApercu]         = useState(null);      // document affiché en plein écran
  const [envoiSite, setEnvoiSite]   = useState("");        // site dont l'envoi est en cours
  const refUrls = useRef([]);                              // aperçus à libérer de la mémoire

  const libererUrls = () => {
    refUrls.current.forEach(u => { try{ URL.revokeObjectURL(u); }catch(e){} });
    refUrls.current = [];
  };

  // Charge la liste et les aperçus de chaque site
  const chargerDocuments = async () => {
    setChargement(true); setErreur("");
    try{
      libererUrls();
      const resultat = {};
      for(const s of SITES){
        const liste = await listerDocuments(s.id);
        const avecApercu = [];
        for(const doc of liste){
          const type = typeDocument(doc.nom);
          let url = null;
          try{ url = await apercuDocument(doc.chemin); if(url) refUrls.current.push(url); }
          catch(e){ url = null; }
          avecApercu.push({ ...doc, type, url });
        }
        resultat[s.id] = avecApercu;
      }
      setParSite(resultat);
    }catch(e){
      setErreur("Impossible de charger les documents pour le moment.");
    }finally{
      setChargement(false);
    }
  };

  // Vérifie le droit d'accès, puis charge les documents
  const verifierAcces = async () => {
    setEtape("verif"); setErreur("");
    try{
      const admin = await appelRPC("is_admin", {});
      const autorise = admin ? true : await appelRPC("client_documents_autorise", {});
      if(admin || autorise){ setEstAdmin(!!admin); setEtape("pret"); chargerDocuments(); }
      else { setEstAdmin(false); setEtape("refuse"); }
    }catch(e){
      deconnexion(); setEtape("connexion");
    }
  };

  useEffect(()=>{
    if(lireSession()) verifierAcces();
    else setEtape("connexion");
    return ()=> libererUrls();
  }, []);

  const seDeconnecter = () => { deconnexion(); setParSite({}); setEstAdmin(false); setEtape("connexion"); };

  // Import d'un ou plusieurs documents (administrateur)
  const importer = async (idSite, listeFichiers) => {
    if(!listeFichiers || !listeFichiers.length) return;
    setEnvoiSite(idSite); setErreur("");
    try{
      for(const f of Array.from(listeFichiers)){ await televerserDocument(idSite, f); }
      await chargerDocuments();
    }catch(e){
      setErreur(e.message === "DROITS_INSUFFISANTS"
        ? "Envoi refusé : connectez-vous avec votre compte administrateur (onglet Admin) avant d'importer."
        : "L'envoi du document a échoué. Réessayez.");
    }finally{
      setEnvoiSite("");
    }
  };

  const supprimer = async (chemin) => {
    setErreur("");
    try{ await supprimerDocument(chemin); await chargerDocuments(); }
    catch(e){ setErreur("La suppression a échoué."); }
  };

  // ---------- vérification ----------
  if(etape === "verif"){
    return (
      <div className="page">
        <div className="carte carte-pad" style={{textAlign:"center",padding:"34px 18px"}}>
          <div style={{width:30,height:30,margin:"0 auto 14px",borderRadius:"50%",
            border:"3px solid var(--gris-200)",borderTopColor:"var(--vert-700)",
            animation:"gea-tourne .8s linear infinite"}}/>
          <div style={{fontSize:14,fontWeight:700,color:"var(--gris-700)"}}>Vérification de l'accès…</div>
        </div>
      </div>
    );
  }

  // ---------- connexion ----------
  if(etape === "connexion"){
    return (
      <div className="page">
        <EcranConnexion
          titre="Documents des terrains"
          sousTitre="Espace réservé aux clients ayant souscrit et réglé leurs frais de dossier."
          avecInscription={false}
          noteAide="Connectez-vous avec le compte (email) de votre dossier. L'accès aux documents s'ouvre une fois vos frais de dossier réglés."
          onConnecte={verifierAcces}/>
      </div>
    );
  }

  // ---------- accès refusé (connecté mais pas à jour) ----------
  if(etape === "refuse"){
    return (
      <div className="page">
        <div className="carte" style={{background:"linear-gradient(135deg,#13502E,#1A6138)",
          border:"none",padding:18,marginBottom:16}}>
          <div style={{color:"#fff",fontSize:18,fontWeight:800}}>Documents des terrains</div>
        </div>
        <div className="carte carte-pad">
          <div style={{display:"flex",gap:10,alignItems:"center",marginBottom:10}}>
            <Lock size={20} color="var(--or-700)"/>
            <div style={{fontSize:14.5,fontWeight:800,color:"var(--gris-700)"}}>Accès réservé</div>
          </div>
          <div style={{fontSize:13,color:"var(--gris-500)",lineHeight:1.55,marginBottom:16}}>
            La consultation des documents est réservée aux clients ayant souscrit et réglé leurs
            frais de dossier. Si vous avez déjà réglé vos frais, contactez votre conseiller
            GEA-HOLDING pour l'activation de votre accès.
          </div>
          <button className="btn btn-ligne" onClick={seDeconnecter}>
            <LogOut size={16}/> Changer de compte
          </button>
        </div>
      </div>
    );
  }

  // ---------- espace documents (accès autorisé) ----------
  return (
    <div className="page">
      <div className="eyebrow">Espace sécurisé</div>
      <h1 className="titre-page">Documents des terrains</h1>
      <p className="sous-titre">Consultation seule — documents non téléchargeables.</p>

      {estAdmin && (
        <div style={{background:"var(--vert-50)",border:"1px solid var(--vert-200,#CDE3D5)",borderRadius:11,
          padding:"9px 12px",marginBottom:14,fontSize:12.5,fontWeight:600,color:"var(--vert-800)"}}>
          Mode administrateur : vous pouvez ajouter ou supprimer des documents pour chaque site.
        </div>
      )}
      {erreur && (
        <div style={{background:"#FBEAE7",color:"#C0392B",fontSize:12.5,fontWeight:600,
          padding:"10px 12px",borderRadius:11,marginBottom:14}}>{erreur}</div>
      )}
      {chargement && (
        <div style={{fontSize:12.5,color:"var(--gris-500)",marginBottom:12}}>Chargement des documents…</div>
      )}

      {SITES.map(s=>{
        const docs = parSite[s.id] || [];
        return (
          <div key={s.id} className="carte carte-pad" style={{marginBottom:16}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",gap:8,marginBottom:10}}>
              <div>
                <div style={{fontSize:14.5,fontWeight:800,color:"var(--vert-800)"}}>{s.ville}</div>
                <div style={{fontSize:11.5,color:"var(--gris-500)"}}>{s.quartier}</div>
              </div>
              {estAdmin && (
                <label style={{cursor:"pointer",display:"inline-flex",alignItems:"center",gap:6,
                  background:"var(--vert-700)",color:"#fff",fontSize:12,fontWeight:700,
                  padding:"7px 11px",borderRadius:9,flex:"0 0 auto",opacity: envoiSite===s.id?0.6:1}}>
                  <Upload size={14}/>{envoiSite===s.id ? "Envoi…" : "Importer"}
                  <input type="file" multiple accept="image/*,application/pdf"
                    style={{display:"none"}} disabled={envoiSite===s.id}
                    onChange={(e)=>{ importer(s.id, e.target.files); e.target.value=""; }}/>
                </label>
              )}
            </div>

            {docs.length === 0 ? (
              <div style={{fontSize:12.5,color:"var(--gris-500)"}}>
                {chargement ? "…" : "Aucun document pour ce site."}
              </div>
            ) : (
              <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8}}
                onContextMenu={(e)=>e.preventDefault()}>
                {docs.map((d,i)=>(
                  <div key={i} style={{position:"relative"}}>
                    <button onClick={()=> d.url && setApercu(d)}
                      style={{display:"block",width:"100%",aspectRatio:"1 / 1",borderRadius:10,overflow:"hidden",
                        border:"1px solid var(--gris-200)",background:"#F4F6F4",padding:0,
                        cursor: d.url?"zoom-in":"default"}}>
                      {d.type==="image" && d.url ? (
                        <img src={d.url} alt={d.nom} draggable="false"
                          style={{width:"100%",height:"100%",objectFit:"cover",pointerEvents:"none"}}/>
                      ) : (
                        <div style={{width:"100%",height:"100%",display:"flex",flexDirection:"column",
                          alignItems:"center",justifyContent:"center",gap:6,color:"var(--gris-500)",padding:6}}>
                          <FileText size={26} color="var(--vert-700)"/>
                          <span style={{fontSize:9.5,fontWeight:700,textAlign:"center",lineHeight:1.2}}>
                            {d.type==="pdf" ? "PDF" : "Fichier"}</span>
                        </div>
                      )}
                    </button>
                    {estAdmin && (
                      <button onClick={()=> supprimer(d.chemin)} title="Supprimer"
                        style={{position:"absolute",top:5,right:5,width:26,height:26,borderRadius:7,
                          background:"rgba(192,57,43,.92)",display:"flex",alignItems:"center",justifyContent:"center"}}>
                        <Trash2 size={13} color="#fff"/>
                      </button>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
        );
      })}

      <div className="carte carte-pad" style={{display:"flex",gap:10,alignItems:"center",marginBottom:8}}>
        <Lock size={18} color="var(--vert-700)"/>
        <div style={{fontSize:12,color:"var(--gris-600)",lineHeight:1.45}}>
          Documents fournis à titre de consultation. La copie, la diffusion ou le téléchargement
          ne sont pas autorisés.
        </div>
      </div>
      <button className="btn btn-ligne" onClick={seDeconnecter}><LogOut size={16}/> Se déconnecter</button>

      {/* visionneuse plein écran — consultation seule */}
      {apercu && (
        <div onClick={()=>setApercu(null)} onContextMenu={(e)=>e.preventDefault()}
          style={{position:"fixed",inset:0,zIndex:50,background:"rgba(0,0,0,.88)",
            display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
          <button onClick={()=>setApercu(null)}
            style={{position:"absolute",top:14,right:14,width:40,height:40,borderRadius:11,
              background:"rgba(255,255,255,.15)",display:"flex",alignItems:"center",justifyContent:"center"}}>
            <X size={20} color="#fff"/>
          </button>
          <div style={{position:"absolute",top:20,left:16,display:"flex",alignItems:"center",gap:6,
            background:"rgba(0,0,0,.45)",padding:"5px 9px",borderRadius:8}}>
            <Lock size={12} color="#fff"/>
            <span style={{fontSize:10.5,fontWeight:700,color:"#fff"}}>Consultation seule</span>
          </div>
          {apercu.type==="image" ? (
            <img src={apercu.url} alt={apercu.nom} draggable="false" onClick={(e)=>e.stopPropagation()}
              style={{maxWidth:"100%",maxHeight:"100%",objectFit:"contain",userSelect:"none"}}/>
          ) : apercu.type==="pdf" ? (
            <iframe title={apercu.nom} src={apercu.url + "#toolbar=0&navpanes=0"}
              onClick={(e)=>e.stopPropagation()}
              style={{width:"100%",height:"100%",border:"none",background:"#fff",borderRadius:8}}/>
          ) : (
            <div onClick={(e)=>e.stopPropagation()} style={{color:"#fff",textAlign:"center"}}>
              <FileText size={40} color="#fff"/>
              <div style={{marginTop:10,fontSize:13}}>Aperçu indisponible pour ce type de fichier.</div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

/* ============================================================
   SECTION 5 — FORMULAIRE DE SOUSCRIPTION
   (sans balise <form> ; intégrations paiement préparées visuellement)
   ============================================================ */
function Souscription(){
  const [f, setF] = useState({
    civilite:"M.", nom:"", prenoms:"", naissance:"", lieuNaissance:"", nationalite:"Ivoirienne",
    profession:"", telephone:"", email:"", residence:"", typePiece:"CNI", numPiece:"",
    site:"yam", mode:"echelonne", apport:"", mensualite:"", contactNom:"", contactTel:""
  });
  const [erreur, setErreur] = useState("");
  const [envoye, setEnvoye] = useState(false);
  const [refDossier, setRefDossier] = useState("");
  const [envoiEnCours, setEnvoiEnCours] = useState(false);   // true pendant l'enregistrement serveur
  const [secoursLocal, setSecoursLocal] = useState(false);   // true si l'enregistrement en ligne a échoué (WhatsApp prend le relais)
  const set = (k,v)=> setF(o=>({ ...o, [k]:v }));

  // référence de secours, générée localement si le serveur est momentanément injoignable
  const refDeSecours = ()=> "GEA-" + new Date().getFullYear() + "-" + Math.floor(1000+Math.random()*9000);

  // Enregistre la souscription dans Supabase (table "souscriptions") via la fonction
  // serveur "creer_souscription", puis affiche l'écran de confirmation + WhatsApp.
  const valider = async ()=>{
    if(!f.nom.trim() || !f.prenoms.trim() || !f.telephone.trim()){
      setErreur("Merci de renseigner au minimum vos nom, prénoms et téléphone.");
      window.scrollTo({ top:0, behavior:"smooth" });
      return;
    }
    setErreur("");
    setEnvoiEnCours(true);
    try{
      const resultat = await appelRPC("creer_souscription", {
        p_civilite:       f.civilite,
        p_nom:            f.nom.trim(),
        p_prenoms:        f.prenoms.trim(),
        p_naissance:      f.naissance,
        p_lieu_naissance: f.lieuNaissance,
        p_nationalite:    f.nationalite,
        p_profession:     f.profession,
        p_telephone:      f.telephone.trim(),
        p_email:          f.email,
        p_residence:      f.residence,
        p_type_piece:     f.typePiece,
        p_num_piece:      f.numPiece,
        p_site_id:        f.site,
        p_mode:           f.mode,
        p_apport:         f.apport ? versNombre(f.apport) : null,
        p_mensualite:     f.mensualite ? versNombre(f.mensualite) : null,
        p_contact_nom:    f.contactNom,
        p_contact_tel:    f.contactTel,
      });
      // le serveur renvoie la référence officielle (ex. GEA-2026-0007)
      setRefDossier(resultat && resultat.reference ? resultat.reference : refDeSecours());
      setSecoursLocal(false);
    }catch(e){
      // enregistrement en ligne indisponible : on NE PERD PAS le client, WhatsApp prend le relais
      setRefDossier(refDeSecours());
      setSecoursLocal(true);
    }finally{
      setEnvoiEnCours(false);
      setEnvoye(true);
      window.scrollTo({ top:0, behavior:"smooth" });
    }
  };

  const champ = (label, k, type="text", ph="") => (
    <div className="champ-bloc">
      <label className="champ-label">{label}</label>
      <input className="champ" type={type} placeholder={ph} value={f[k]} onChange={(e)=>set(k,e.target.value)}/>
    </div>
  );
  const champMont = (label, k) => (
    <div className="champ-bloc">
      <label className="champ-label">{label}</label>
      <div className="champ-wrap">
        <input className="champ champ-mont" inputMode="numeric" placeholder="0"
          value={f[k] ? versNombre(f[k]).toLocaleString("fr-FR") : ""}
          onChange={(e)=>set(k, String(versNombre(e.target.value) || ""))}/>
        <span className="champ-unite">FCFA</span>
      </div>
    </div>
  );
  const select = (label, k, options) => (
    <div className="champ-bloc">
      <label className="champ-label">{label}</label>
      <select className="champ" value={f[k]} onChange={(e)=>set(k,e.target.value)}>
        {options.map(o=><option key={o.v} value={o.v}>{o.l}</option>)}
      </select>
    </div>
  );

  // --- écran de confirmation ---
  if(envoye){
    const site = SITES.find(s=>s.id===f.site);
    return (
      <div className="page">
        <div className="carte carte-pad" style={{textAlign:"center",
          background:"linear-gradient(180deg,#fff,var(--vert-50))",borderColor:"var(--vert-100)"}}>
          <div style={{width:62,height:62,borderRadius:"50%",margin:"0 auto 14px",
            background:"var(--vert-ok)",display:"flex",alignItems:"center",justifyContent:"center"}}>
            <Check size={32} color="#fff"/>
          </div>
          <h1 className="titre-page" style={{fontSize:20}}>
            {secoursLocal ? "Demande prête à envoyer" : "Souscription enregistrée"}
          </h1>
          <p className="sous-titre" style={{marginBottom:16}}>
            {secoursLocal
              ? <>Merci {f.civilite} {f.nom}. L'enregistrement en ligne est momentanément indisponible : envoyez votre demande sur WhatsApp, un conseiller GEA-HOLDING la traitera et vous recontactera.</>
              : <>Merci {f.civilite} {f.nom}. Votre souscription a bien été enregistrée auprès de GEA-HOLDING. Un conseiller vous recontactera. Vous pouvez aussi la transmettre dès maintenant sur WhatsApp.</>}
          </p>
          <div className="carte carte-pad" style={{textAlign:"left",background:"#fff"}}>
            <div className="info-fixe"><span className="lbl">Référence dossier</span><span className="val">{refDossier}</span></div>
            <div className="info-fixe"><span className="lbl">Site</span><span className="val">{site.ville} — {site.quartier}</span></div>
            <div className="info-fixe"><span className="lbl">Mode</span><span className="val">{f.mode==="comptant"?"Comptant":"Échelonné"}</span></div>
            {f.apport && <div className="info-fixe"><span className="lbl">Apport</span><span className="val">{formaterFCFA(versNombre(f.apport))}</span></div>}
            <div className="info-fixe"><span className="lbl">Téléphone</span><span className="val">{f.telephone}</span></div>
          </div>

          {/* envoi du lead sur WhatsApp — un bouton par conseiller (lien fiable, surtout sur mobile) */}
          {WHATSAPP_GEA.map((c,i)=>(
            <a key={i} className={"btn " + (i===0 ? "btn-vert" : "btn-ligne")}
              href={lienWhatsAppLead(f, site, refDossier, c.numero)}
              target="_blank" rel="noopener noreferrer"
              style={{marginTop:i===0?16:10,textDecoration:"none"}}>
              <MessageCircle size={18}/> Envoyer à {c.nom} sur WhatsApp
            </a>
          ))}
          <div style={{fontSize:11.5,color:"var(--gris-400)",textAlign:"center",marginTop:8,lineHeight:1.45}}>
            Choisissez un conseiller : WhatsApp s'ouvre avec votre demande déjà pré-remplie. Vérifiez puis appuyez sur « Envoyer ».
          </div>

          <div className="conseil" style={{marginTop:16,textAlign:"left"}}>
            <div className="ic"><Bell/></div>
            <div><div className="ttl">PROCHAINE ÉTAPE</div>
              <div className="txt">Préparez votre pièce d'identité. À la mise en production, vous recevrez
              un récapitulatif PDF et un lien de signature électronique.</div></div>
          </div>
          <button className="btn btn-ligne" style={{marginTop:16}} onClick={()=>setEnvoye(false)}>
            Nouvelle souscription
          </button>
        </div>
      </div>
    );
  }

  // --- formulaire ---
  return (
    <div className="page">
      <div className="eyebrow">Devenir propriétaire</div>
      <h1 className="titre-page">Formulaire de souscription</h1>
      <p className="sous-titre">Renseignez vos informations. Vos données restent confidentielles.</p>

      {erreur && (
        <div className="alerte" style={{marginBottom:16}}>
          <AlertTriangle size={20}/><div className="txt" style={{color:"var(--rouge)",fontWeight:600}}>{erreur}</div>
        </div>
      )}

      {/* Identité */}
      <div className="carte carte-pad" style={{marginBottom:16}}>
        <div className="eyebrow" style={{marginBottom:12}}>1 · Identité</div>
        {select("Civilité","civilite",[{v:"M.",l:"M."},{v:"Mme",l:"Mme"},{v:"Mlle",l:"Mlle"}])}
        {champ("Nom","nom","text","Votre nom")}
        {champ("Prénoms","prenoms","text","Vos prénoms")}
        <div style={{display:"flex",gap:10}}>
          <div style={{flex:1}}>{champ("Date de naissance","naissance","date")}</div>
          <div style={{flex:1}}>{champ("Lieu de naissance","lieuNaissance","text","Ville")}</div>
        </div>
        {champ("Nationalité","nationalite")}
        {champ("Profession","profession","text","Votre profession")}
      </div>

      {/* Coordonnées */}
      <div className="carte carte-pad" style={{marginBottom:16}}>
        <div className="eyebrow" style={{marginBottom:12}}>2 · Coordonnées</div>
        {champ("Téléphone","telephone","tel","+225 ...")}
        {champ("E-mail","email","email","vous@email.com")}
        {champ("Résidence / adresse","residence","text","Commune, quartier")}
      </div>

      {/* Pièce d'identité */}
      <div className="carte carte-pad" style={{marginBottom:16}}>
        <div className="eyebrow" style={{marginBottom:12}}>3 · Pièce d'identité</div>
        {select("Type de pièce","typePiece",[{v:"CNI",l:"CNI"},{v:"Passeport",l:"Passeport"},
          {v:"Attestation",l:"Attestation d'identité"},{v:"Permis",l:"Permis de conduire"}])}
        {champ("Numéro de la pièce","numPiece","text","N° du document")}
      </div>

      {/* Projet & plan */}
      <div className="carte carte-pad" style={{marginBottom:16}}>
        <div className="eyebrow" style={{marginBottom:12}}>4 · Votre projet</div>
        {select("Site choisi","site",SITES.map(s=>({v:s.id,l:`${s.ville} — ${s.quartier}`})))}
        {select("Mode de paiement","mode",[{v:"echelonne",l:"Échelonné (jusqu'à 48 mois)"},{v:"comptant",l:"Comptant"}])}
        {f.mode==="echelonne" && (
          <div style={{display:"flex",gap:10}}>
            <div style={{flex:1}}>{champMont("Apport initial","apport")}</div>
            <div style={{flex:1}}>{champMont("Mensualité","mensualite")}</div>
          </div>
        )}
      </div>

      {/* Personne à prévenir */}
      <div className="carte carte-pad" style={{marginBottom:16}}>
        <div className="eyebrow" style={{marginBottom:12}}>5 · Personne à prévenir</div>
        {champ("Nom complet","contactNom","text","Proche à contacter")}
        {champ("Téléphone","contactTel","tel","+225 ...")}
      </div>

      {/* Paiement (préparé visuellement) */}
      <div className="carte carte-pad" style={{marginBottom:16}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12}}>
          <div className="eyebrow" style={{margin:0}}>6 · Moyens de paiement</div>
          <span className="tag-soon">Bientôt</span>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:9}}>
          {[["Orange Money","#FF7900"],["MTN MoMo","#FFCC00"],["Wave","#1DC8FF"],
            ["Mobile Money","#13502E"],["Carte bancaire","#444"]].map(([nom,col])=>(
            <div key={nom} style={{display:"flex",alignItems:"center",gap:9,padding:"11px 12px",
              borderRadius:12,border:"1.5px solid var(--gris-200)",background:"var(--gris-50)",opacity:.85}}>
              <span style={{width:26,height:26,borderRadius:7,background:col,flex:"0 0 auto",
                display:"flex",alignItems:"center",justifyContent:"center"}}>
                <CreditCard size={14} color="#fff"/></span>
              <span style={{fontSize:12.5,fontWeight:700,color:"var(--gris-700)"}}>{nom}</span>
            </div>
          ))}
        </div>
        <div style={{fontSize:11.5,color:"var(--gris-400)",marginTop:10,lineHeight:1.45}}>
          Le paiement en ligne (Mobile Money, Orange, MTN, Wave, carte) sera activé à la mise en production.
        </div>
      </div>

      {/* Mention de confidentialité — protection des données personnelles */}
      <div style={{padding:"13px 14px",marginBottom:16,background:"var(--vert-50)",
        border:"1px solid var(--vert-100)",borderRadius:14,display:"flex",gap:10,alignItems:"flex-start"}}>
        <Lock size={16} color="var(--vert-600)" style={{flex:"0 0 auto",marginTop:2}}/>
        <div style={{fontSize:11.5,color:"var(--gris-700)",lineHeight:1.5}}>
          <strong style={{color:"var(--vert-600)"}}>Confidentialité.</strong> Les informations recueillies servent uniquement
          à traiter votre demande et à permettre à un conseiller GEA-HOLDING de vous recontacter. Elles sont enregistrées
          dans le registre sécurisé de GEA-HOLDING (et, si vous le souhaitez, transmises via WhatsApp) et ne sont ni vendues ni cédées à des
          tiers. Conformément à la loi ivoirienne sur la
          protection des données personnelles, vous disposez d'un droit d'accès, de rectification et de suppression de vos
          données ; pour l'exercer, utilisez les coordonnées en bas de page. En validant, vous consentez à ce traitement.
        </div>
      </div>

      <button className="btn btn-vert" onClick={valider} disabled={envoiEnCours}
        style={envoiEnCours ? {opacity:.7, cursor:"default"} : undefined}>
        {envoiEnCours
          ? <>Enregistrement en cours…</>
          : <><ShieldCheck size={18}/> Valider ma souscription</>}
      </button>
      <div style={{fontSize:11,color:"var(--gris-400)",textAlign:"center",marginTop:10,
        display:"flex",alignItems:"center",justifyContent:"center",gap:6}}>
        <MessageCircle size={12}/> Après validation, choisissez le conseiller à contacter sur WhatsApp
      </div>
    </div>
  );
}

/* ============================================================
   SECTION 6 — ESPACE CLIENT (dossier, versements, graphiques, assistant)
   ============================================================ */
/* ============================================================
   SECTION 6 — ESPACE CLIENT (connecté à Supabase)
   ------------------------------------------------------------
   Le client se connecte avec son EMAIL + un MOT DE PASSE (vrai
   système d'authentification Supabase). Son dossier (montants,
   versements) est lu en toute sécurité via get_mon_dossier(), qui
   s'appuie sur le compte connecté : un client ne peut voir QUE son
   propre dossier. Le bouton « dossier de démonstration » affiche un
   exemple fictif, sans aucune connexion ni accès aux données réelles.
   ============================================================ */

/* ------------------------------------------------------------
   Traduction des messages d'erreur d'authentification en français
   ------------------------------------------------------------ */
function messageErreur(e){
  const m = String((e && e.message) || e || "").toLowerCase();
  if(m.includes("invalid login")) return "Email ou mot de passe incorrect.";
  if(m.includes("email not confirmed")) return "Votre email n'est pas encore confirmé. Vérifiez votre boîte mail.";
  if(m.includes("already registered") || m.includes("already been registered")) return "Un compte existe déjà pour cet email. Connectez-vous.";
  if(m.includes("signups not allowed") || m.includes("signup is disabled")) return "La création de compte est désactivée. Contactez votre conseiller.";
  if(m.includes("password should be") || m.includes("at least")) return "Mot de passe trop court (8 caractères minimum).";
  if(m.includes("rate limit") || m.includes("too many")) return "Trop de tentatives. Patientez un instant avant de réessayer.";
  if(m.includes("failed to fetch") || m.includes("networkerror")) return "Connexion au serveur impossible. Réessayez dans un instant.";
  return (e && e.message) ? e.message : "Une erreur est survenue. Réessayez.";
}

/* ------------------------------------------------------------
   Champ « mot de passe » avec icône œil (afficher / masquer)
   ------------------------------------------------------------ */
function ChampMotDePasse({ valeur, onChange, placeholder, onEnter, autoComplete }){
  const [voir, setVoir] = useState(false);
  return (
    <div style={{position:"relative"}}>
      <input className="champ" type={voir ? "text" : "password"}
        placeholder={placeholder || "Votre mot de passe"} value={valeur} onChange={onChange}
        autoComplete={autoComplete || "current-password"} style={{paddingRight:46}}
        onKeyDown={(e)=>{ if(e.key === "Enter" && onEnter) onEnter(); }}/>
      <button type="button" onClick={()=>setVoir(v=>!v)}
        aria-label={voir ? "Masquer le mot de passe" : "Afficher le mot de passe"}
        style={{position:"absolute",right:6,top:"50%",transform:"translateY(-50%)",
          background:"none",border:"none",padding:8,cursor:"pointer",
          color:"var(--gris-500)",display:"inline-flex"}}>
        {voir ? <EyeOff size={18}/> : <Eye size={18}/>}
      </button>
    </div>
  );
}

/* ------------------------------------------------------------
   Écran de connexion réutilisable (Espace client ET Admin)
   Gère : connexion · inscription · mot de passe oublié.
   Appelle onConnecte(session) une fois la connexion réussie.
   ------------------------------------------------------------ */
function EcranConnexion({ titre, sousTitre, avecInscription, noteAide, onConnecte }){
  const [mode, setMode]             = useState("connexion"); // "connexion" | "inscription" | "oubli"
  const [email, setEmail]           = useState("");
  const [motDePasse, setMotDePasse] = useState("");
  const [erreur, setErreur]         = useState("");
  const [info, setInfo]             = useState("");
  const [chargement, setChargement] = useState(false);

  const changerMode = (m)=>{ setMode(m); setErreur(""); setInfo(""); };

  const faireConnexion = async ()=>{
    if(!email.trim() || !motDePasse){ setErreur("Saisissez votre email et votre mot de passe."); return; }
    setErreur(""); setInfo(""); setChargement(true);
    try{
      const session = await connexionEmail(email, motDePasse);
      await onConnecte(session);              // le parent prend le relais (chargement du dossier / tableau de bord)
    }catch(e){ setErreur(messageErreur(e)); setChargement(false); }
  };

  const faireInscription = async ()=>{
    if(!email.trim() || !motDePasse){ setErreur("Saisissez votre email et choisissez un mot de passe."); return; }
    if(motDePasse.length < 8){ setErreur("Choisissez un mot de passe d'au moins 8 caractères."); return; }
    setErreur(""); setInfo(""); setChargement(true);
    try{
      const { session } = await inscriptionEmail(email, motDePasse);
      if(session){ await onConnecte(session); }
      else{
        setInfo("Compte créé. Un email de confirmation vous a été envoyé : cliquez sur le lien, puis connectez-vous.");
        setMode("connexion"); setChargement(false);
      }
    }catch(e){ setErreur(messageErreur(e)); setChargement(false); }
  };

  const faireOubli = async ()=>{
    if(!email.trim()){ setErreur("Saisissez votre email pour recevoir le lien de réinitialisation."); return; }
    setErreur(""); setInfo(""); setChargement(true);
    try{
      await motDePasseOublie(email);
      setInfo("Si un compte existe pour cet email, un lien de réinitialisation vient d'être envoyé.");
      setChargement(false);
    }catch(e){ setErreur(messageErreur(e)); setChargement(false); }
  };

  const action = mode === "inscription" ? faireInscription : mode === "oubli" ? faireOubli : faireConnexion;
  const libelleBouton = chargement
    ? "Veuillez patienter…"
    : mode === "inscription" ? "Créer mon compte"
    : mode === "oubli" ? "Envoyer le lien"
    : "Se connecter";

  return (
    <>
      <div className="carte" style={{background:"linear-gradient(135deg,#13502E,#1A6138)",
        border:"none",padding:18,marginBottom:16}}>
        <div style={{color:"#fff",fontSize:18,fontWeight:800}}>{titre}</div>
        <div style={{color:"rgba(255,255,255,.75)",fontSize:12.5,marginTop:3}}>{sousTitre}</div>
      </div>

      <div className="carte carte-pad" style={{marginBottom:16}}>
        <div className="champ-bloc">
          <label className="champ-label">Adresse email</label>
          <input className="champ" type="email" placeholder="vous@exemple.com" value={email}
            onChange={(e)=>setEmail(e.target.value)} autoComplete="email" inputMode="email"
            onKeyDown={(e)=>{ if(e.key === "Enter") action(); }}/>
        </div>

        {mode !== "oubli" && (
          <div className="champ-bloc">
            <label className="champ-label">Mot de passe</label>
            <ChampMotDePasse valeur={motDePasse} onChange={(e)=>setMotDePasse(e.target.value)}
              onEnter={action}
              autoComplete={mode === "inscription" ? "new-password" : "current-password"}/>
            {mode === "connexion" && (
              <button type="button" onClick={()=>changerMode("oubli")}
                style={{marginTop:8,background:"none",border:"none",padding:0,cursor:"pointer",
                  color:"var(--vert-700)",fontSize:12.5,fontWeight:700}}>
                Mot de passe oublié ?
              </button>
            )}
          </div>
        )}

        {erreur && (
          <div style={{background:"#FBEAE7",color:"#C0392B",fontSize:12.5,fontWeight:600,
            padding:"10px 12px",borderRadius:11,marginBottom:12}}>{erreur}</div>
        )}
        {info && (
          <div style={{background:"#E8F3EC",color:"#1A6138",fontSize:12.5,fontWeight:600,
            padding:"10px 12px",borderRadius:11,marginBottom:12}}>{info}</div>
        )}

        <button className="btn btn-vert" onClick={action} disabled={chargement}>
          {mode === "oubli" ? <KeyRound size={17}/> : <LogIn size={17}/>} {libelleBouton}
        </button>

        {mode === "connexion" && avecInscription && (
          <button className="btn btn-ligne" style={{marginTop:10}} onClick={()=>changerMode("inscription")}>
            Créer un compte
          </button>
        )}
        {mode !== "connexion" && (
          <button className="btn btn-ligne" style={{marginTop:10}} onClick={()=>changerMode("connexion")}>
            Retour à la connexion
          </button>
        )}
      </div>

      {noteAide && (
        <div className="conseil">
          <div className="ic"><MessageCircle/></div>
          <div>
            <div className="ttl">BESOIN D'AIDE ?</div>
            <div className="txt">{noteAide}</div>
          </div>
        </div>
      )}
    </>
  );
}

/* ------------------------------------------------------------
   Écran « Définir un nouveau mot de passe »
   Affiché automatiquement quand l'utilisateur arrive depuis le lien
   reçu par email. Utilise le jeton de récupération pour enregistrer
   le nouveau mot de passe, puis renvoie vers la connexion.
   ------------------------------------------------------------ */
function EcranNouveauMotDePasse({ jeton, messageLien, onTermine }){
  const [mdp, setMdp]                   = useState("");
  const [confirmation, setConfirmation] = useState("");
  const [erreur, setErreur]             = useState("");
  const [chargement, setChargement]     = useState(false);
  const [reussi, setReussi]             = useState(false);

  const enregistrer = async ()=>{
    if(mdp.length < 8){ setErreur("Choisissez un mot de passe d'au moins 8 caractères."); return; }
    if(mdp !== confirmation){ setErreur("Les deux mots de passe ne sont pas identiques."); return; }
    setErreur(""); setChargement(true);
    try{
      await definirNouveauMotDePasse(jeton, mdp);
      deconnexion();                       // on repart d'une session propre
      setReussi(true);
      window.scrollTo({ top:0, behavior:"smooth" });
    }catch(e){ setErreur(messageErreur(e)); }
    finally{ setChargement(false); }
  };

  // ----- lien invalide ou expiré -----
  if(messageLien){
    return (
      <div className="page">
        <div className="carte" style={{background:"linear-gradient(135deg,#13502E,#1A6138)",
          border:"none",padding:18,marginBottom:16}}>
          <div style={{color:"#fff",fontSize:18,fontWeight:800}}>Réinitialisation du mot de passe</div>
        </div>
        <div className="carte carte-pad">
          <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:8}}>
            <AlertTriangle size={18} color="#C0392B"/>
            <div style={{fontSize:14.5,fontWeight:800,color:"var(--gris-700)"}}>Lien expiré ou invalide</div>
          </div>
          <div style={{fontSize:13,color:"var(--gris-500)",lineHeight:1.55,marginBottom:16}}>{messageLien}</div>
          <button className="btn btn-vert" onClick={onTermine}>Retour à la connexion</button>
        </div>
      </div>
    );
  }

  // ----- mot de passe enregistré -----
  if(reussi){
    return (
      <div className="page">
        <div className="carte" style={{background:"linear-gradient(135deg,#13502E,#1A6138)",
          border:"none",padding:18,marginBottom:16}}>
          <div style={{color:"#fff",fontSize:18,fontWeight:800}}>Mot de passe modifié</div>
        </div>
        <div className="carte carte-pad" style={{textAlign:"center"}}>
          <div style={{width:54,height:54,borderRadius:"50%",background:"var(--vert-50)",
            display:"flex",alignItems:"center",justifyContent:"center",margin:"4px auto 14px"}}>
            <Check size={28} color="var(--vert-600)"/>
          </div>
          <div style={{fontSize:15,fontWeight:800,color:"var(--gris-700)",marginBottom:6}}>
            Votre nouveau mot de passe est enregistré.
          </div>
          <div style={{fontSize:13,color:"var(--gris-500)",lineHeight:1.55,marginBottom:18}}>
            Vous pouvez maintenant vous connecter avec ce mot de passe.
          </div>
          <button className="btn btn-vert" onClick={onTermine}>
            <LogIn size={17}/> Aller à la connexion
          </button>
        </div>
      </div>
    );
  }

  // ----- saisie du nouveau mot de passe -----
  return (
    <div className="page">
      <div className="carte" style={{background:"linear-gradient(135deg,#13502E,#1A6138)",
        border:"none",padding:18,marginBottom:16}}>
        <div style={{color:"#fff",fontSize:18,fontWeight:800}}>Nouveau mot de passe</div>
        <div style={{color:"rgba(255,255,255,.75)",fontSize:12.5,marginTop:3}}>
          Choisissez le mot de passe qui protégera votre accès.
        </div>
      </div>

      <div className="carte carte-pad">
        <div className="champ-bloc">
          <label className="champ-label">Nouveau mot de passe</label>
          <ChampMotDePasse valeur={mdp} onChange={(e)=>setMdp(e.target.value)}
            placeholder="Au moins 8 caractères" autoComplete="new-password" onEnter={enregistrer}/>
        </div>
        <div className="champ-bloc">
          <label className="champ-label">Confirmez le mot de passe</label>
          <ChampMotDePasse valeur={confirmation} onChange={(e)=>setConfirmation(e.target.value)}
            placeholder="Saisissez à nouveau" autoComplete="new-password" onEnter={enregistrer}/>
        </div>

        {erreur && (
          <div style={{background:"#FBEAE7",color:"#C0392B",fontSize:12.5,fontWeight:600,
            padding:"10px 12px",borderRadius:11,marginBottom:12}}>{erreur}</div>
        )}

        <button className="btn btn-vert" onClick={enregistrer} disabled={chargement}>
          <KeyRound size={17}/> {chargement ? "Enregistrement…" : "Enregistrer le mot de passe"}
        </button>
      </div>
    </div>
  );
}


