function EspaceClient(){
  const [etape, setEtape]     = useState("verif");   // "verif" | "connexion" | "chargement" | "sans_dossier" | "dossier"
  const [dossier, setDossier] = useState(null);
  const [erreur, setErreur]   = useState("");
  const [demo, setDemo]       = useState(false);

  // Charge le dossier du client connecté (avec tentative de rattachement par email si nécessaire)
  const chargerDossier = async () => {
    setEtape("chargement"); setErreur("");
    try{
      let d = await appelRPC("get_mon_dossier", {});
      if(!d){
        await appelRPC("lier_mon_dossier", {});      // rattache le compte au dossier créé pour son email
        d = await appelRPC("get_mon_dossier", {});
      }
      if(d){
        setDossier(d); setDemo(false); setEtape("dossier");
        window.scrollTo({ top:0, behavior:"smooth" });
      }else{
        setEtape("sans_dossier");
      }
    }catch(e){
      deconnexion();
      setEtape("connexion");
      setErreur(messageErreur(e));
    }
  };

  // Si une session est déjà ouverte, on rejoint directement le dossier
  useEffect(()=>{
    if(lireSession()) chargerDossier();
    else setEtape("connexion");
  }, []);

  const voirDemo = () => {
    setDossier(DOSSIER_DEMO); setDemo(true); setErreur(""); setEtape("dossier");
    window.scrollTo({ top:0, behavior:"smooth" });
  };
  const seDeconnecter = () => {
    deconnexion(); setDossier(null); setDemo(false); setErreur(""); setEtape("connexion");
  };

  // ---------- écran de vérification / chargement ----------
  if(etape === "verif" || etape === "chargement"){
    return (
      <div className="page">
        <div className="carte carte-pad" style={{textAlign:"center",padding:"34px 18px"}}>
          <div style={{width:30,height:30,margin:"0 auto 14px",borderRadius:"50%",
            border:"3px solid var(--gris-200)",borderTopColor:"var(--vert-700)",
            animation:"gea-tourne .8s linear infinite"}}/>
          <div style={{fontSize:14,fontWeight:700,color:"var(--gris-700)"}}>Chargement de votre espace…</div>
        </div>
      </div>
    );
  }

  // ---------- écran de connexion (email + mot de passe) ----------
  if(etape === "connexion"){
    return (
      <div className="page">
        {erreur && (
          <div style={{background:"#FBEAE7",color:"#C0392B",fontSize:12.5,fontWeight:600,
            padding:"10px 12px",borderRadius:11,marginBottom:14}}>{erreur}</div>
        )}
        <EcranConnexion
          titre="Espace client"
          sousTitre="Suivez votre acquisition et vos versements en temps réel."
          avecInscription={true}
          noteAide="Connectez-vous avec l'email communiqué à votre conseiller lors de la souscription. Première visite : créez votre compte avec ce même email."
          onConnecte={chargerDossier}/>
        <button className="btn btn-ligne" onClick={voirDemo}>
          Voir un dossier de démonstration
        </button>
      </div>
    );
  }

  // ---------- compte connecté mais aucun dossier rattaché ----------
  if(etape === "sans_dossier"){
    return (
      <div className="page">
        <div className="carte" style={{background:"linear-gradient(135deg,#13502E,#1A6138)",
          border:"none",padding:18,marginBottom:16}}>
          <div style={{color:"#fff",fontSize:18,fontWeight:800}}>Espace client</div>
          <div style={{color:"rgba(255,255,255,.75)",fontSize:12.5,marginTop:3}}>
            Compte connecté.</div>
        </div>
        <div className="carte carte-pad" style={{marginBottom:16}}>
          <div style={{fontSize:14.5,fontWeight:800,color:"var(--gris-700)",marginBottom:8}}>
            Aucun dossier rattaché à ce compte
          </div>
          <div style={{fontSize:13,color:"var(--gris-500)",lineHeight:1.55,marginBottom:16}}>
            Votre connexion a réussi, mais aucun dossier ne correspond encore à cet email.
            Vérifiez avec votre conseiller GEA-HOLDING que l'email enregistré dans votre dossier
            est bien celui que vous venez d'utiliser.
          </div>
          <button className="btn btn-vert" onClick={chargerDossier}>Réessayer</button>
          <button className="btn btn-ligne" style={{marginTop:10}} onClick={seDeconnecter}>
            <LogOut size={16}/> Se déconnecter
          </button>
        </div>
      </div>
    );
  }

  // ---------- dossier chargé ----------
  const cl    = dossier.client;
  const vers  = Array.isArray(dossier.versements) ? dossier.versements : [];
  const payes = vers.filter(v => v.etat === "ok");
  const totalPaye = payes.reduce((s,v)=> s + (Number(v.montant) || 0), 0);
  const prixTotal = Number(cl.prix_total) || PRIX_TERRAIN;
  const solde     = Math.max(0, prixTotal - totalPaye);
  const mensualite = Number(cl.mensualite) || 0;
  const resteMois = mensualite > 0 ? Math.ceil(solde / mensualite) : 0;
  const pct       = Math.min(100, Math.round((totalPaye / prixTotal) * 100));

  let cumul = 0;
  const histo = payes.map((v,i)=>{ cumul += Number(v.montant) || 0; return { m:"V"+(i+1), paye:Math.round(cumul/1000) }; });
  const donut = [{ n:"Payé", v:totalPaye, c:"#2E7D4F" }, { n:"Reste", v:solde, c:"#ECEFEC" }];

  const fmtDate = (iso)=>{ if(!iso) return ""; const p=String(iso).split("-"); return p.length===3 ? `${p[2]}/${p[1]}/${p[0]}` : iso; };
  const prochaine = vers.find(v => v.etat !== "ok");
  const etatLbl   = { ok:["ok","Payé"], att:["att","À venir"], ret:["ret","En retard"] };
  const solde0    = solde === 0;

  return (
    <div className="page">
      {demo && (
        <div style={{background:"#FFF6E0",border:"1px solid var(--or-400)",color:"var(--or-700)",
          fontSize:12.5,fontWeight:700,padding:"9px 12px",borderRadius:11,marginBottom:14,
          display:"flex",alignItems:"center",gap:8}}>
          <AlertTriangle size={15}/> Mode démonstration — données fictives (aucune connexion réelle)
        </div>
      )}
      {/* en-tête dossier */}
      <div className="carte" style={{background:"linear-gradient(135deg,#13502E,#1A6138)",
        border:"none",padding:18,marginBottom:16}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
          <div>
            <div style={{color:"rgba(255,255,255,.7)",fontSize:12}}>Bonjour {cl.civilite} {cl.nom},</div>
            <div style={{color:"#fff",fontSize:18,fontWeight:800}}>Votre acquisition</div>
            <div style={{color:"#E9C25A",fontSize:12,fontWeight:700,marginTop:2}}>
              {cl.ville} — {cl.quartier}</div>
          </div>
          <button onClick={seDeconnecter}
            style={{color:"rgba(255,255,255,.85)",fontSize:11.5,fontWeight:700,
              border:"1px solid rgba(255,255,255,.3)",borderRadius:9,padding:"6px 10px",flex:"0 0 auto"}}>
            Se déconnecter
          </button>
        </div>
        <div style={{fontSize:11,color:"rgba(255,255,255,.6)",marginTop:10}}>Dossier N° {cl.reference}</div>
      </div>

      {/* progression + donut */}
      <div className="carte carte-pad" style={{marginBottom:16}}>
        <div style={{display:"flex",alignItems:"center",gap:14}}>
          <div style={{width:120,height:120,position:"relative",flex:"0 0 auto"}}>
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={donut} dataKey="v" innerRadius={40} outerRadius={56} startAngle={90}
                  endAngle={-270} stroke="none">
                  {donut.map((d,i)=><Cell key={i} fill={d.c}/>)}
                </Pie>
              </PieChart>
            </ResponsiveContainer>
            <div style={{position:"absolute",inset:0,display:"flex",flexDirection:"column",
              alignItems:"center",justifyContent:"center"}}>
              <div style={{fontSize:22,fontWeight:800,color:"var(--vert-800)"}}>{pct}%</div>
              <div style={{fontSize:9,color:"var(--gris-500)",fontWeight:700}}>ACQUIS</div>
            </div>
          </div>
          <div style={{flex:1}}>
            <div style={{fontSize:12,color:"var(--gris-500)",fontWeight:600}}>Déjà versé</div>
            <div style={{fontSize:20,fontWeight:800,color:"var(--vert-800)"}}>{formaterFCFA(totalPaye)}</div>
            <div style={{fontSize:12,color:"var(--gris-500)",fontWeight:600,marginTop:8}}>Solde restant</div>
            <div style={{fontSize:16,fontWeight:800}}>{formaterFCFA(solde)}</div>
            {!solde0 && mensualite>0 &&
              <div style={{fontSize:11.5,color:"var(--gris-400)",marginTop:6}}>Encore ~{resteMois} mensualités</div>}
            {solde0 &&
              <div style={{fontSize:11.5,color:"var(--vert-700)",fontWeight:700,marginTop:6}}>Acquisition soldée 🎉</div>}
          </div>
        </div>
      </div>

      {/* graphique de progression */}
      {histo.length > 0 && (
      <div className="carte carte-pad" style={{marginBottom:16}}>
        <div className="eyebrow" style={{marginBottom:4}}>Progression des versements</div>
        <div style={{fontSize:12,color:"var(--gris-500)",marginBottom:10}}>Cumul payé (en milliers de FCFA)</div>
        <div style={{height:150}}>
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={histo} margin={{top:5,right:5,left:-18,bottom:0}}>
              <defs><linearGradient id="gv" x1="0" y1="0" x2="0" y2="1">
                <stop offset="0" stopColor="#2E7D4F" stopOpacity=".5"/>
                <stop offset="1" stopColor="#2E7D4F" stopOpacity="0"/></linearGradient></defs>
              <CartesianGrid strokeDasharray="3 3" stroke="#ECEFEC"/>
              <XAxis dataKey="m" tick={{fontSize:10,fill:"#9AA39D"}} axisLine={false} tickLine={false}/>
              <YAxis tick={{fontSize:10,fill:"#9AA39D"}} axisLine={false} tickLine={false}/>
              <Tooltip formatter={(v)=>[v+" k FCFA","Cumul"]} labelStyle={{fontWeight:700}}/>
              <Area type="monotone" dataKey="paye" stroke="#13502E" strokeWidth={2.5} fill="url(#gv)"/>
            </AreaChart>
          </ResponsiveContainer>
        </div>
      </div>
      )}

      {/* tableau de versements */}
      <div className="carte carte-pad" style={{marginBottom:16}}>
        <div className="eyebrow" style={{marginBottom:10}}>Tableau de versements</div>
        {vers.length === 0 ? (
          <div style={{fontSize:12.5,color:"var(--gris-500)"}}>Aucun versement enregistré pour le moment.</div>
        ) : (
        <table className="tab">
          <thead><tr><th>Date</th><th>Échéance</th><th>Montant</th><th>État</th></tr></thead>
          <tbody>
            {vers.map((v,i)=>(
              <tr key={i}>
                <td style={{color:"var(--gris-500)"}}>{fmtDate(v.date)}</td>
                <td>{v.libelle}</td>
                <td>{formaterFCFA(v.montant)}</td>
                <td><span className={"etat "+(etatLbl[v.etat] ? etatLbl[v.etat][0] : "att")}>
                  {etatLbl[v.etat] ? etatLbl[v.etat][1] : v.etat}</span></td>
              </tr>
            ))}
          </tbody>
        </table>
        )}
      </div>

      {/* rappel prochaine échéance */}
      {prochaine && (
      <div className="carte carte-pad" style={{marginBottom:16,display:"flex",gap:12,alignItems:"center",
        background:"var(--or-100)",borderColor:"var(--or-400)"}}>
        <div style={{width:40,height:40,borderRadius:11,background:"var(--or-500)",flex:"0 0 auto",
          display:"flex",alignItems:"center",justifyContent:"center"}}><Bell size={20} color="#fff"/></div>
        <div>
          <div style={{fontWeight:800,fontSize:13.5}}>Prochaine échéance : {fmtDate(prochaine.date)}</div>
          <div style={{fontSize:12.5,color:"var(--gris-600)"}}>{prochaine.libelle} de {formaterFCFA(prochaine.montant)} à régler.</div>
        </div>
      </div>
      )}

      {/* assistant + motivation */}
      <div className="conseil" style={{marginBottom:8}}>
        <div className="ic"><MessageCircle/></div>
        <div>
          <div className="ttl">VOTRE ASSISTANT GEA-HOLDING</div>
          <div className="txt">
            {solde0 ? (
              <>Félicitations {cl.nom} 🎉 Votre terrain à {cl.ville} est <b>entièrement payé</b>.
              Votre conseiller vous accompagne pour la suite des démarches. 🌿</>
            ) : (
              <>Bravo {cl.nom} 👏 Vous avez franchi <b>{pct}%</b> du chemin !
              {mensualite>0 && <> En maintenant votre rythme, votre terrain à {cl.ville} sera
              entièrement payé d'ici <b>{dateFin(resteMois)}</b>.</>} Continuez, la propriété est à
              portée de main. 🌿</>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

/* ============================================================
   SECTION 7 — TABLEAU DE BORD ADMINISTRATEUR
   ============================================================ */
const COULEURS_SITE = { yam:"#13502E", jac:"#2E7D4F", songon:"#C9A227" };
function nomSite(id){ const s = SITES.find(x => x.id === id); return s ? s.ville : (id || "—"); }

/* Fiche détaillée d'un souscripteur (dépliable) + bouton de transmission au service commercial. */
function FicheSouscripteur({ s, ouvert, onToggle, onTransmettre, enCours }){
  const echelonne  = s.mode !== "comptant";
  const transmise  = String(s.statut || "").toLowerCase() === "transmis";
  const dh         = s.cree_le ? new Date(s.cree_le) : null;
  const dateCourt  = dh ? dh.toLocaleDateString("fr-FR") : "";
  const heureCourt = dh ? dh.toLocaleTimeString("fr-FR", { hour:"2-digit", minute:"2-digit" }) : "";
  const lien       = lienWhatsAppCommercial(s, SERVICE_COMMERCIAL.numero);

  // ligne "label : valeur" (n'affiche rien si la valeur est vide)
  const ligne = (label, val)=>{
    if(val === undefined || val === null || String(val).trim() === "") return null;
    return (
      <div style={{display:"flex",justifyContent:"space-between",gap:14,padding:"7px 0",borderBottom:"1px solid var(--gris-100)"}}>
        <span style={{fontSize:11.5,color:"var(--gris-500)",flex:"0 0 auto"}}>{label}</span>
        <span style={{fontSize:12.5,fontWeight:600,color:"var(--gris-700)",textAlign:"right",wordBreak:"break-word"}}>{val}</span>
      </div>
    );
  };
  const titre = (Icone, txt)=>(
    <div style={{display:"flex",alignItems:"center",gap:7,margin:"15px 0 3px",color:"var(--vert-700)"}}>
      <Icone size={14}/>
      <span style={{fontSize:11,fontWeight:800,letterSpacing:".4px",textTransform:"uppercase"}}>{txt}</span>
    </div>
  );
  const recap = (label, val, fort)=>(
    <div style={{display:"flex",justifyContent:"space-between",gap:12,padding:"3px 0"}}>
      <span style={{fontSize:12,color: fort ? "var(--vert-800)" : "var(--gris-500)",fontWeight: fort ? 800 : 500}}>{label}</span>
      <span style={{fontSize:12.5,color: fort ? "var(--vert-800)" : "var(--gris-700)",fontWeight: fort ? 800 : 700}}>{val}</span>
    </div>
  );

  const badge = transmise
    ? <span style={{display:"inline-flex",alignItems:"center",gap:4,fontSize:10.5,fontWeight:800,color:"var(--vert-ok)",background:"var(--vert-50)",border:"1px solid var(--vert-100)",padding:"2px 8px",borderRadius:20}}><Check size={11}/> Transmise</span>
    : <span style={{display:"inline-flex",alignItems:"center",gap:4,fontSize:10.5,fontWeight:800,color:"var(--or-700)",background:"var(--or-100)",padding:"2px 8px",borderRadius:20}}>Nouvelle</span>;

  return (
    <div>
      {/* en-tête cliquable */}
      <div onClick={onToggle} style={{cursor:"pointer",display:"flex",alignItems:"center",gap:10,padding:"12px 13px"}}>
        <div style={{flex:1,minWidth:0}}>
          <div style={{display:"flex",alignItems:"center",gap:8,flexWrap:"wrap"}}>
            <span style={{fontWeight:800,fontSize:13.5,color:"var(--gris-700)"}}>
              {s.civilite ? s.civilite + " " : ""}{String(s.nom || "").trim()} {s.prenoms || ""}
            </span>
            {badge}
          </div>
          <div style={{fontSize:11.5,color:"var(--gris-500)",marginTop:3,display:"flex",flexWrap:"wrap",gap:"2px 8px"}}>
            <span style={{fontWeight:700,color:"var(--vert-700)"}}>{s.reference}</span>
            <span>· {nomSite(s.site_id)}</span>
            <span>· {echelonne ? "Échelonné" : "Comptant"}</span>
            {dateCourt && <span>· {dateCourt}{heureCourt ? " à " + heureCourt : ""}</span>}
          </div>
        </div>
        <ChevronRight size={18} style={{color:"var(--gris-400)",flex:"0 0 auto",transform: ouvert ? "rotate(90deg)" : "none",transition:"transform .2s"}}/>
      </div>

      {/* fiche détaillée */}
      {ouvert && (
        <div style={{padding:"0 13px 14px",borderTop:"1px solid var(--gris-100)"}}>
          {titre(User, "Identité")}
          {ligne("Civilité", s.civilite)}
          {ligne("Nom", String(s.nom || "").trim())}
          {ligne("Prénoms", s.prenoms)}
          {ligne("Naissance", [s.naissance, s.lieu_naissance].filter(Boolean).join(" à "))}
          {ligne("Nationalité", s.nationalite)}
          {ligne("Profession", s.profession)}
          {ligne("Pièce", [s.type_piece, s.num_piece].filter(Boolean).join(" · "))}

          {titre(Phone, "Contact")}
          <div style={{display:"flex",flexWrap:"wrap",gap:"6px 16px",padding:"7px 0"}}>
            {s.telephone && <a href={"tel:" + s.telephone} style={{fontSize:12.5,fontWeight:700,color:"var(--vert-700)",textDecoration:"none",display:"inline-flex",alignItems:"center",gap:5}}><Phone size={13}/> {formaterTel(s.telephone)}</a>}
            {s.email && <a href={"mailto:" + s.email} style={{fontSize:12,color:"var(--gris-500)",textDecoration:"none",display:"inline-flex",alignItems:"center",gap:5}}><Mail size={13}/> {s.email}</a>}
          </div>
          {ligne("Résidence", s.residence)}
          {(s.contact_nom || s.contact_tel) && ligne("Personne à prévenir", [s.contact_nom, s.contact_tel].filter(Boolean).join(" — "))}

          {titre(MapPin, "Projet & paiement")}
          {ligne("Site", nomSite(s.site_id))}
          {ligne("Mode de paiement", echelonne ? "Échelonné" : "Comptant")}
          {echelonne && ligne("Apport", s.apport ? formaterFCFA(s.apport) : null)}
          {echelonne && ligne("Mensualité", s.mensualite ? formaterFCFA(s.mensualite) : null)}
          {ligne("Frais de dossier", formaterFCFA(FRAIS_DOSSIER))}
          {ligne("Souscrit le", dh ? dh.toLocaleString("fr-FR") : null)}
          {transmise && s.transmis_le && ligne("Transmise le", new Date(s.transmis_le).toLocaleString("fr-FR"))}

          {/* récapitulatif financier */}
          <div style={{background:"var(--vert-50)",border:"1px solid var(--vert-100)",borderRadius:12,padding:"10px 12px",marginTop:13}}>
            <div style={{fontSize:10.5,fontWeight:800,letterSpacing:".4px",color:"var(--vert-700)",textTransform:"uppercase",marginBottom:6}}>Récapitulatif</div>
            {echelonne ? (
              <>
                {recap("Prix du terrain", formaterFCFA(PRIX_TERRAIN))}
                {recap("Frais de dossier", formaterFCFA(FRAIS_DOSSIER))}
                {recap("Montant global", formaterFCFA(PRIX_TERRAIN + FRAIS_DOSSIER), true)}
              </>
            ) : (
              <>
                {recap("Prix comptant", formaterFCFA(PRIX_COMPTANT))}
                {recap("Frais de dossier", formaterFCFA(FRAIS_DOSSIER))}
                {recap("À régler", formaterFCFA(PRIX_COMPTANT + FRAIS_DOSSIER), true)}
              </>
            )}
          </div>

          {/* bouton de transmission au service commercial */}
          <a href={lien} target="_blank" rel="noopener noreferrer"
            onClick={()=> onTransmettre(s)}
            className="btn btn-vert" style={{marginTop:13,opacity: enCours ? .7 : 1}}>
            <MessageCircle size={17}/> {transmise ? "Transmettre à nouveau" : "Transmettre au service commercial"}
          </a>
          <div style={{fontSize:11,color:"var(--gris-400)",textAlign:"center",marginTop:7,lineHeight:1.5}}>
            WhatsApp s'ouvre avec le dossier complet, pré-rempli vers le {SERVICE_COMMERCIAL.nom} ({formaterTel(SERVICE_COMMERCIAL.numero)}).
          </div>
        </div>
      )}
    </div>
  );
}

/* Section "Souscriptions reçues" de l'espace Admin : recherche, filtres, fiches dépliables. */
function SectionSouscripteurs({ souscriptions }){
  const [recherche, setRecherche] = useState("");
  const [filtre, setFiltre]       = useState("toutes");   // "toutes" | "nouvelles" | "transmises"
  const [ouvert, setOuvert]       = useState(null);        // id de la fiche dépliée
  const [maj, setMaj]             = useState({});          // mises à jour locales après transmission
  const [enCours, setEnCours]     = useState(null);        // id en cours de transmission

  const liste = (souscriptions || []).map(s => ({ ...s, ...(maj[s.id] || {}) }));
  const estTransmise = (s)=> String(s.statut || "").toLowerCase() === "transmis";
  const nbNouvelles  = liste.filter(s => !estTransmise(s)).length;
  const nbTransmises = liste.filter(s =>  estTransmise(s)).length;

  const q = recherche.trim().toLowerCase();
  const filtrees = liste.filter(s => {
    if(filtre === "nouvelles"  &&  estTransmise(s)) return false;
    if(filtre === "transmises" && !estTransmise(s)) return false;
    if(!q) return true;
    return [s.nom, s.prenoms, s.reference, s.telephone, s.email]
      .filter(Boolean).some(v => String(v).toLowerCase().includes(q));
  });

  const transmettre = async (s)=>{
    setEnCours(s.id);
    try{
      const r = await appelRPC("transmettre_souscription", { p_id: s.id });
      setMaj(m => ({ ...m, [s.id]: { statut:"transmis", transmis_le:(r && r.transmis_le) || new Date().toISOString() } }));
    }catch(_){
      // l'envoi WhatsApp a tout de même eu lieu : on marque quand même la fiche comme transmise
      setMaj(m => ({ ...m, [s.id]: { statut:"transmis", transmis_le:new Date().toISOString() } }));
    }finally{
      setEnCours(null);
    }
  };

  const puce = (val, libelle, n)=>(
    <button onClick={()=>setFiltre(val)} style={{
      border:"none",cursor:"pointer",fontSize:12,fontWeight:700,padding:"6px 12px",borderRadius:20,
      background: filtre===val ? "var(--vert-700)" : "var(--gris-100)",
      color:     filtre===val ? "#fff" : "var(--gris-500)"}}>
      {libelle}{n != null ? " (" + n + ")" : ""}
    </button>
  );

  return (
    <div className="carte carte-pad" style={{marginTop:16}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:4}}>
        <div className="eyebrow">Souscriptions reçues</div>
        <span style={{fontSize:12,fontWeight:800,color:"var(--vert-700)",background:"var(--vert-50)",padding:"3px 10px",borderRadius:20}}>
          {liste.length}
        </span>
      </div>
      <div style={{fontSize:12,color:"var(--gris-500)",marginBottom:12}}>
        Cliquez sur un souscripteur pour ouvrir sa fiche complète et la transmettre au service commercial.
      </div>

      {liste.length > 0 && (
        <>
          <input className="champ" placeholder="Rechercher (nom, référence, téléphone…)"
            value={recherche} onChange={(e)=>setRecherche(e.target.value)} style={{marginBottom:10}}/>
          <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:14}}>
            {puce("toutes", "Toutes", liste.length)}
            {puce("nouvelles", "Nouvelles", nbNouvelles)}
            {puce("transmises", "Transmises", nbTransmises)}
          </div>
        </>
      )}

      {filtrees.length > 0 ? (
        <div style={{display:"flex",flexDirection:"column",gap:10}}>
          {filtrees.map((s,i)=>{
            const cle = s.id || ("idx" + i);
            return (
              <div key={cle} style={{border:"1px solid var(--gris-200)",borderRadius:13,background:"#fff",overflow:"hidden"}}>
                <FicheSouscripteur
                  s={s}
                  ouvert={ouvert === cle}
                  onToggle={()=> setOuvert(o => o === cle ? null : cle)}
                  onTransmettre={transmettre}
                  enCours={enCours === s.id}/>
              </div>
            );
          })}
        </div>
      ) : (
        <div style={{fontSize:13,color:"var(--gris-500)",padding:"6px 0"}}>
          {liste.length === 0
            ? "Aucune souscription reçue pour le moment."
            : "Aucune souscription ne correspond à votre recherche."}
        </div>
      )}
    </div>
  );
}

function Admin(){
  const [etat, setEtat]     = useState("verif");   // "verif" | "connexion" | "chargement" | "refuse" | "ok"
  const [data, setData]     = useState(null);
  const [souscriptions, setSouscriptions] = useState([]);   // demandes reçues depuis le site
  const [erreur, setErreur] = useState("");

  // Vérifie le droit admin côté serveur, puis charge les données réelles
  const chargerTableau = async () => {
    setEtat("chargement"); setErreur("");
    try{
      const admin = await appelRPC("is_admin", {});
      if(!admin){ setEtat("refuse"); return; }
      const d = await appelRPC("admin_dashboard", {});
      setData(d);
      // liste des souscriptions reçues (n'empêche pas l'affichage du tableau si elle échoue)
      try{
        const s = await appelRPC("lister_souscriptions", {});
        setSouscriptions(Array.isArray(s) ? s : []);
      }catch(_){
        setSouscriptions([]);
      }
      setEtat("ok");
      window.scrollTo({ top:0, behavior:"smooth" });
    }catch(e){
      deconnexion(); setEtat("connexion"); setErreur(messageErreur(e));
    }
  };

  useEffect(()=>{
    if(lireSession()) chargerTableau();
    else setEtat("connexion");
  }, []);

  const seDeconnecter = () => { deconnexion(); setData(null); setErreur(""); setEtat("connexion"); };

  // ---------- vérification / chargement ----------
  if(etat === "verif" || etat === "chargement"){
    return (
      <div className="page">
        <div className="carte carte-pad" style={{textAlign:"center",padding:"34px 18px"}}>
          <div style={{width:30,height:30,margin:"0 auto 14px",borderRadius:"50%",
            border:"3px solid var(--gris-200)",borderTopColor:"var(--vert-700)",
            animation:"gea-tourne .8s linear infinite"}}/>
          <div style={{fontSize:14,fontWeight:700,color:"var(--gris-700)"}}>Vérification de l'accès administrateur…</div>
        </div>
      </div>
    );
  }

  // ---------- connexion administrateur ----------
  if(etat === "connexion"){
    return (
      <div className="page">
        {erreur && (
          <div style={{background:"#FBEAE7",color:"#C0392B",fontSize:12.5,fontWeight:600,
            padding:"10px 12px",borderRadius:11,marginBottom:14}}>{erreur}</div>
        )}
        <EcranConnexion
          titre="Espace administrateur"
          sousTitre="Accès réservé à l'équipe GEA-HOLDING."
          avecInscription={false}
          noteAide="Connectez-vous avec votre compte administrateur. En cas d'oubli, utilisez « Mot de passe oublié ? »."
          onConnecte={chargerTableau}/>
      </div>
    );
  }

  // ---------- compte connecté sans droits admin ----------
  if(etat === "refuse"){
    return (
      <div className="page">
        <div className="carte" style={{background:"linear-gradient(135deg,#13502E,#1A6138)",
          border:"none",padding:18,marginBottom:16}}>
          <div style={{color:"#fff",fontSize:18,fontWeight:800}}>Espace administrateur</div>
        </div>
        <div className="carte carte-pad">
          <div style={{fontSize:14.5,fontWeight:800,color:"var(--gris-700)",marginBottom:8}}>
            Accès non autorisé
          </div>
          <div style={{fontSize:13,color:"var(--gris-500)",lineHeight:1.55,marginBottom:16}}>
            Le compte connecté n'a pas les droits d'administrateur. Si vous pensez qu'il s'agit
            d'une erreur, contactez le responsable de la plateforme.
          </div>
          <button className="btn btn-ligne" onClick={seDeconnecter}>
            <LogOut size={16}/> Se déconnecter
          </button>
        </div>
      </div>
    );
  }

  // ---------- tableau de bord (DONNÉES RÉELLES) ----------
  const d = data || {};
  const moisFr = ["janv.","févr.","mars","avr.","mai","juin","juil.","août","sept.","oct.","nov.","déc."];
  const fmtMois = (ym)=>{ const p = String(ym).split("-"); return p.length >= 2 ? (moisFr[(+p[1]) - 1] || ym) : ym; };
  const encaissements = (d.encaissements_mois || []).slice().reverse()
    .map(m => ({ mois: fmtMois(m.mois), v: Math.round((Number(m.total) || 0) / 1000) }));   // milliers FCFA
  const parSite = (d.par_site || []).map(s => ({ n: nomSite(s.site_id), v: s.n, c: COULEURS_SITE[s.site_id] || "#2E7D4F" }));
  const derniers = d.derniers || [];
  const compact = (n)=>{ n = Number(n) || 0;
    if(n >= 1000000) return (Math.round(n/100000)/10).toString().replace(".",",") + " M";
    if(n >= 1000) return Math.round(n/1000) + " k";
    return String(n); };

  return (
    <div className="page">
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:10}}>
        <div>
          <div className="eyebrow">Pilotage commercial</div>
          <h1 className="titre-page">Tableau de bord</h1>
        </div>
        <button className="btn btn-ligne" onClick={seDeconnecter}
          style={{width:"auto",padding:"8px 12px",fontSize:12.5,flex:"0 0 auto"}}>
          <LogOut size={15}/> Déconnexion
        </button>
      </div>
      <p className="sous-titre">Données en temps réel — projet GEA FONCIER.</p>

      {/* statistiques clés (réelles) */}
      <div className="stats">
        <div className="stat">
          <div className="ic" style={{background:"var(--vert-50)",color:"var(--vert-700)"}}><Users size={17}/></div>
          <div className="v">{d.nb_clients != null ? d.nb_clients : 0}</div><div className="l">Clients</div>
        </div>
        <div className="stat">
          <div className="ic" style={{background:"var(--vert-50)",color:"var(--vert-700)"}}><Receipt size={17}/></div>
          <div className="v">{d.nb_versements != null ? d.nb_versements : 0}</div><div className="l">Versements</div>
        </div>
        <div className="stat">
          <div className="ic" style={{background:"var(--or-100)",color:"var(--or-700)"}}><Banknote size={17}/></div>
          <div className="v">{compact(d.total_encaisse)}</div><div className="l">Encaissé (FCFA)</div>
        </div>
        <div className="stat">
          <div className="ic" style={{background:"var(--rouge-bg)",color:"var(--rouge)"}}><Clock size={17}/></div>
          <div className="v">{d.nb_retards != null ? d.nb_retards : 0}</div><div className="l">Retards</div>
        </div>
      </div>

      {/* encaissements mensuels */}
      {encaissements.length > 0 ? (
        <div className="carte carte-pad" style={{marginBottom:16}}>
          <div className="eyebrow" style={{marginBottom:4}}>Encaissements</div>
          <div style={{fontSize:12,color:"var(--gris-500)",marginBottom:10}}>6 derniers mois (milliers FCFA)</div>
          <div style={{height:150}}>
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={encaissements} margin={{top:5,right:5,left:-22,bottom:0}}>
                <CartesianGrid strokeDasharray="3 3" stroke="#ECEFEC" vertical={false}/>
                <XAxis dataKey="mois" tick={{fontSize:10,fill:"#9AA39D"}} axisLine={false} tickLine={false}/>
                <YAxis tick={{fontSize:10,fill:"#9AA39D"}} axisLine={false} tickLine={false}/>
                <Tooltip formatter={(v)=>[v+" k FCFA","Encaissé"]} cursor={{fill:"#F3F8F4"}}/>
                <Bar dataKey="v" fill="#2E7D4F" radius={[6,6,0,0]} barSize={26}/>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      ) : (
        <div className="carte carte-pad" style={{marginBottom:16}}>
          <div className="eyebrow" style={{marginBottom:6}}>Encaissements</div>
          <div style={{fontSize:13,color:"var(--gris-500)"}}>Aucun encaissement enregistré pour le moment.</div>
        </div>
      )}

      {/* répartition par site */}
      {parSite.length > 0 && (
        <div className="carte carte-pad" style={{marginBottom:16}}>
          <div className="eyebrow" style={{marginBottom:10}}>Clients par site</div>
          <div style={{display:"flex",alignItems:"center",gap:10}}>
            <div style={{width:110,height:110,flex:"0 0 auto"}}>
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie data={parSite} dataKey="v" innerRadius={32} outerRadius={52} stroke="none">
                    {parSite.map((d2,i)=><Cell key={i} fill={d2.c}/>)}
                  </Pie>
                </PieChart>
              </ResponsiveContainer>
            </div>
            <div style={{flex:1}}>
              {parSite.map((s,i)=>(
                <div key={i} style={{display:"flex",alignItems:"center",gap:8,marginBottom:8}}>
                  <span style={{width:11,height:11,borderRadius:3,background:s.c}}/>
                  <span style={{fontSize:13,fontWeight:600,flex:1}}>{s.n}</span>
                  <span style={{fontSize:13,fontWeight:800}}>{s.v}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* derniers dossiers */}
      <div className="carte carte-pad">
        <div className="eyebrow" style={{marginBottom:10}}>Derniers dossiers</div>
        {derniers.length > 0 ? (
          <table className="tab">
            <thead><tr><th>Client</th><th>Site</th><th>Référence</th></tr></thead>
            <tbody>
              {derniers.map((x,i)=>(
                <tr key={i}>
                  <td>{String(x.nom||"").trim()} {x.prenom||""}</td>
                  <td style={{color:"var(--gris-500)"}}>{nomSite(x.site_id)}</td>
                  <td style={{fontWeight:700}}>{x.reference}</td>
                </tr>
              ))}
            </tbody>
          </table>
        ) : (
          <div style={{fontSize:13,color:"var(--gris-500)"}}>Aucun dossier enregistré pour le moment.</div>
        )}
      </div>

      {/* souscriptions reçues — tableau de bord détaillé (recherche, filtres, fiche, transmission) */}
      <SectionSouscripteurs souscriptions={souscriptions} />
    </div>
  );
}

/* ============================================================
   APPLICATION PRINCIPALE — état global, navigation, pied de page
   ============================================================ */
const ONGLETS = [
  { id:"accueil",      libelle:"Accueil",    Icone:Home },
  { id:"projets",      libelle:"Projets",    Icone:MapPin },
  { id:"simulateur",   libelle:"Simulateur", Icone:Calculator },
  { id:"morcellement", libelle:"Documents",  Icone:MapIcon },
  { id:"souscription", libelle:"Souscrire",  Icone:FileText },
  { id:"client",       libelle:"Espace client", Icone:User },
  { id:"admin",        libelle:"Admin",      Icone:LayoutDashboard },
];

/* ──────────────────────────────────────────────────────────────
   INTERRUPTEUR — MODE PUBLIC
   true  = version en ligne : l'« Espace client » est visible (l'accès
           aux dossiers est protégé par email + mot de passe), et
           l'onglet « Admin » est MASQUÉ pour vos visiteurs.
   false = mode développement : tout est visible pour vos essais.

   👉 ACCÈS DISCRET À L'ONGLET ADMIN (même quand MODE_PUBLIC = true) :
      tapez 5 fois de suite sur le logo en haut de l'écran.
      L'onglet « Admin » apparaît alors. Tapez encore 5 fois pour le masquer.

   IMPORTANT : ce geste ne fait QUE révéler l'onglet. La vraie sécurité
   du tableau de bord repose sur la connexion administrateur (email +
   mot de passe) et la vérification du droit « admin » côté serveur :
   sans compte administrateur valide, le tableau de bord reste inaccessible.
   ────────────────────────────────────────────────────────────── */
const MODE_PUBLIC = true;

export default function App(){
  const [ongletActif, setOngletActif] = useState("accueil");
  const [modeAdmin, setModeAdmin] = useState(false);
  const [adminDebloque, setAdminDebloque] = useState(false); // tableau de bord rendu visible via 5 tappes sur le logo
  const [recuperation, setRecuperation]   = useState(null);  // lien « nouveau mot de passe » reçu par email : { jeton } | { erreur } | null
  const refDebloque  = useRef(false);
  const refTaps      = useRef(0);
  const refMinuteur  = useRef(null);

  // Accès discret au tableau de bord : 5 tappes sur le logo l'affichent / le masquent.
  const tapLogo = ()=>{
    refTaps.current += 1;
    clearTimeout(refMinuteur.current);
    refMinuteur.current = setTimeout(()=>{ refTaps.current = 0; }, 1200);
    if(refTaps.current >= 5){
      refTaps.current = 0;
      const nouveau = !refDebloque.current;
      refDebloque.current = nouveau;
      setAdminDebloque(nouveau);
      setOngletActif(nouveau ? "admin" : "accueil");
    }
  };

  // Onglets affichés : en mode public l'« Admin » reste caché, sauf s'il a été débloqué.
  const ongletsAffiches = (MODE_PUBLIC && !adminDebloque)
    ? ONGLETS.filter(o => o.id !== "admin")
    : ONGLETS;
  const [mediasParSite, setMediasParSite] = useState({
    yam:    mediasIntegres("yam"),
    jac:    mediasIntegres("jac"),
    songon: mediasIntegres("songon"),
  });

  // chargement au démarrage : photos intégrées au build + photos ajoutées via l'admin (stockage local)
  useEffect(()=>{
    (async ()=>{
      const charges = {};
      for(const s of SITES){
        const base = mediasIntegres(s.id);
        const urls = await chargerPhotos(s.id);
        const enPlus = urls
          .filter(u => !(PHOTOS_SITE[s.id] || []).includes(u))
          .map(url => ({ type:"photo", url }));
        charges[s.id] = [ ...base, ...enPlus ];
      }
      setMediasParSite(prev => ({ ...prev, ...charges }));
    })();
  }, []);

  // retour en haut à chaque changement d'onglet
  useEffect(()=>{ window.scrollTo({ top:0, behavior:"smooth" }); }, [ongletActif]);

  // au chargement : si l'adresse contient un lien de récupération (venu de l'email),
  // on bascule sur l'écran « nouveau mot de passe » et on nettoie l'adresse.
  useEffect(()=>{
    const lien = lireLienRecuperation();
    if(lien){ setRecuperation(lien); nettoyerAdresse(); }
  }, []);

  // import de médias (photos compressées + enregistrées ; vidéos pour la session)
  const gererImport = async (idSite, fichiers)=>{
    const nouveaux = [];
    for(const fichier of Array.from(fichiers)){
      if(fichier.type.startsWith("image/")){
        const dataURL = await compresserImage(fichier);
        nouveaux.push({ type:"photo", url:dataURL });
      } else if(fichier.type.startsWith("video/")){
        nouveaux.push({ type:"video", url:URL.createObjectURL(fichier) });
      }
    }
    if(!nouveaux.length) return;
    setMediasParSite(prev=>{
      const maj = { ...prev, [idSite]:[ ...(prev[idSite]||[]), ...nouveaux ] };
      sauvegarderPhotos(idSite, maj[idSite]
        .filter(m=>m.type==="photo" && !(PHOTOS_SITE[idSite] || []).includes(m.url))
        .map(m=>m.url));
      return maj;
    });
  };

  // suppression d'un média
  const supprimerMedia = (idSite, index)=>{
    setMediasParSite(prev=>{
      const liste = [ ...(prev[idSite]||[]) ];
      liste.splice(index,1);
      sauvegarderPhotos(idSite, liste
        .filter(m=>m.type==="photo" && !(PHOTOS_SITE[idSite] || []).includes(m.url))
        .map(m=>m.url));
      return { ...prev, [idSite]:liste };
    });
  };

  const allerA = (id)=> setOngletActif(id);

  // ÉCRAN PRIORITAIRE : nouveau mot de passe (l'utilisateur arrive depuis le lien email).
  // Affiché seul, avec le logo, sans navigation, pour qu'il aille au bout sans distraction.
  if(recuperation){
    return (
      <div className="gea-app">
        <style dangerouslySetInnerHTML={{ __html: css }}/>
        <div className="gea-shell gea-shell--solo">
          <header className="entete">
            <span style={{display:"inline-flex"}}><LogoCompact/></span>
          </header>
          <main>
            <EcranNouveauMotDePasse
              jeton={recuperation.jeton}
              messageLien={recuperation.erreur}
              onTermine={()=>{ setRecuperation(null); setOngletActif("client"); }}/>
          </main>
        </div>
      </div>
    );
  }

  return (
    <div className="gea-app">
      <style dangerouslySetInnerHTML={{ __html: css }}/>
      <div className="gea-shell">

        {/* EN-TÊTE */}
        <header className="entete">
          <span onClick={tapLogo} style={{cursor:"pointer",display:"inline-flex"}}>
            <LogoCompact/>
          </span>
          {(!MODE_PUBLIC || adminDebloque) && (
            <button className="entete-admin" onClick={()=>setModeAdmin(v=>!v)}>
              <span>{modeAdmin ? "Admin actif" : "Espace admin"}</span>
              <span className={"bascule" + (modeAdmin ? " on":"")}><span/></span>
            </button>
          )}
        </header>

        {/* NAVIGATION */}
        <nav className="nav-onglets">
          {ongletsAffiches.map(({id,libelle,Icone})=>(
            <button key={id} className={"onglet" + (ongletActif===id ? " actif":"")}
              onClick={()=>setOngletActif(id)}>
              <Icone/><span>{libelle}</span>
            </button>
          ))}
        </nav>

        {/* CONTENU */}
        <main>
          {ongletActif==="accueil"      && <Accueil allerA={allerA}/>}
          {ongletActif==="projets"      && <Projets allerA={allerA} mediasParSite={mediasParSite}
            modeAdmin={modeAdmin} gererImport={gererImport} supprimerMedia={supprimerMedia}/>}
          {ongletActif==="simulateur"   && <Simulateur allerA={allerA}/>}
          {ongletActif==="morcellement" && <Documents/>}
          {ongletActif==="souscription" && <Souscription/>}
          {ongletActif==="client" && <EspaceClient/>}
          {(adminDebloque || !MODE_PUBLIC) && ongletActif==="admin"  && <Admin/>}
        </main>

        {/* PIED DE PAGE */}
        <footer style={{background:"linear-gradient(180deg,#13502E,#0E3A20)",padding:"26px 18px 30px"}}>
          <LogoComplet/>
          <div className="sep" style={{background:"rgba(255,255,255,.12)",margin:"20px 0 14px"}}/>
          {/* contact : numéros WhatsApp cliquables, visibles sur toutes les pages */}
          <div style={{display:"flex",flexDirection:"column",gap:9,alignItems:"center",marginBottom:16}}>
            {WHATSAPP_GEA.map((c,i)=>(
              <a key={i} href={"https://wa.me/" + c.numero} target="_blank" rel="noopener noreferrer"
                style={{display:"inline-flex",alignItems:"center",gap:8,textDecoration:"none",
                  color:"#fff",fontSize:13.5,fontWeight:700}}>
                <MessageCircle size={15} color="#E9C25A"/> {c.nom} · {formaterTel(c.numero)}
              </a>
            ))}
          </div>
          <div style={{display:"flex",flexWrap:"wrap",gap:"6px 16px",justifyContent:"center",marginBottom:14}}>
            {ongletsAffiches.map(o=>(
              <button key={o.id} onClick={()=>setOngletActif(o.id)}
                style={{fontSize:12,fontWeight:600,color:"rgba(255,255,255,.75)"}}>{o.libelle}</button>
            ))}
          </div>
          <div style={{textAlign:"center",fontSize:11,color:"rgba(255,255,255,.5)",lineHeight:1.6}}>
            © {new Date().getFullYear()} GEA-HOLDING SAU · Tous droits réservés<br/>
            Plateforme de gestion et de suivi foncier
          </div>
        </footer>

      </div>
    </div>
  );
}
